import React, { useState } from 'react';
import { Button } from './ui/Button';
import { FoodItem, MealLog, MealType, MacroTargets } from '../types';
import { MOCK_COMMON_FOODS, NUTRIENT_INFO } from '../data/nutrientData';
import { parseFoodLog } from '../services/geminiService';

interface NutritionTrackerProps {
  logs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  targets: MacroTargets;
}

const MEAL_TYPES: MealType[] = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];

export const NutritionTracker: React.FC<NutritionTrackerProps> = ({ logs, onAddFood, targets }) => {
  const [activeTab, setActiveTab] = useState<'log' | 'analysis'>('log');
  const [isAdding, setIsAdding] = useState(false);
  const [selectedMeal, setSelectedMeal] = useState<MealType>('Breakfast');
  const [searchQuery, setSearchQuery] = useState('');
  const [aiInput, setAiInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedNutrient, setSelectedNutrient] = useState<string | null>(null);

  // -- Derived Data --
  const consumedMacros = logs.reduce((acc, log) => ({
    calories: acc.calories + log.food.calories,
    protein: acc.protein + log.food.protein,
    carbs: acc.carbs + log.food.carbs,
    fat: acc.fat + log.food.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Consolidate micros
  const consumedMicros: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        // Simple normalization if Gemini returns name variations, though strict list is preferred
        consumedMicros[name] = (consumedMicros[name] || 0) + (amount as number);
      });
    }
  });

  // -- Handlers --
  const handleAiParse = async () => {
    if(!aiInput.trim()) return;
    setIsAiLoading(true);
    const foods = await parseFoodLog(aiInput);
    foods.forEach(f => onAddFood(selectedMeal, f));
    setIsAiLoading(false);
    setAiInput('');
    setIsAdding(false);
  };

  const handleManualAdd = (food: FoodItem) => {
    onAddFood(selectedMeal, food);
    setIsAdding(false);
  };

  // -- Render Helpers --
  const ProgressBar = ({ current, target, colorClass, label, unit }: any) => {
    const pct = Math.min((current / target) * 100, 100);
    return (
      <div className="mb-4">
        <div className="flex justify-between text-sm font-bold text-slate-700 mb-1">
          <span>{label}</span>
          <span>{Math.round(current)} / {Math.round(target)}{unit}</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-500 ${colorClass}`} style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const NutrientDetailModal = () => {
    if (!selectedNutrient) return null;
    const info = NUTRIENT_INFO[selectedNutrient];
    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4" onClick={() => setSelectedNutrient(null)}>
        <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl animate-fade-in" onClick={e => e.stopPropagation()}>
          <div className="flex justify-between items-start mb-4">
             <h3 className="text-2xl font-black text-slate-800">{selectedNutrient}</h3>
             <button onClick={() => setSelectedNutrient(null)} className="text-slate-400 hover:text-slate-800 text-xl font-bold">×</button>
          </div>

          {info ? (
            <div className="space-y-4">
              <p className="text-slate-600 leading-relaxed">{info.description}</p>

              <div className="flex justify-between items-center bg-slate-50 p-4 rounded-xl border border-slate-100">
                 <span className="font-bold text-slate-600">Daily Target</span>
                 <span className="font-black text-xl text-slate-800">{info.dailyValue}</span>
              </div>

              <div>
                <h4 className="font-bold text-sm text-brand-600 uppercase mb-2">Good Sources</h4>
                <div className="flex flex-wrap gap-2">
                  {info.sources.map(s => (
                    <span key={s} className="bg-brand-50 text-brand-800 px-3 py-1 rounded-full text-sm font-medium border border-brand-100">{s}</span>
                  ))}
                </div>
              </div>

              {info.caution && (
                <div className="bg-amber-50 p-4 rounded-xl border border-amber-100 text-amber-800 text-sm">
                  <strong>⚠️ Note: </strong> {info.caution}
                </div>
              )}
            </div>
          ) : (
            <p>No educational data available for this nutrient.</p>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Sub-tabs */}
      <div className="flex gap-2 bg-slate-100 p-1 rounded-xl w-fit">
        <button
          onClick={() => setActiveTab('log')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'log' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Food Log
        </button>
        <button
          onClick={() => setActiveTab('analysis')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Analysis & Info
        </button>
      </div>

      {activeTab === 'log' && (
        <div className="animate-fade-in">
          {!isAdding ? (
            <>
              {/* Daily Summary Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-6 flex justify-between items-center">
                <div>
                   <h3 className="font-bold text-slate-500 text-sm uppercase">Calories Remaining</h3>
                   <div className="text-4xl font-black text-slate-800">
                     {Math.max(0, Math.round(targets.calories - consumedMacros.calories))}
                   </div>
                </div>
                <div className="text-right">
                   <div className="text-sm text-slate-500">Eaten</div>
                   <div className="font-bold text-xl text-brand-600">{Math.round(consumedMacros.calories)} kcal</div>
                </div>
              </div>

              <div className="space-y-6">
                {MEAL_TYPES.map(type => {
                  const mealLogs = logs.filter(l => l.type === type);
                  const mealCals = mealLogs.reduce((acc, l) => acc + l.food.calories, 0);

                  return (
                    <div key={type} className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                      <div className="bg-slate-50 p-4 flex justify-between items-center border-b border-slate-100">
                        <h4 className="font-bold text-slate-800">{type}</h4>
                        <span className="text-sm font-medium text-slate-500">{mealCals} kcal</span>
                      </div>
                      <div className="divide-y divide-slate-100">
                        {mealLogs.length === 0 ? (
                          <div className="p-4 text-center text-slate-400 text-sm italic">No food logged</div>
                        ) : (
                          mealLogs.map(log => (
                            <div key={log.id} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors">
                               <div>
                                 <div className="font-medium text-slate-800">
                                   {log.food.name} 
                                   <span className="text-brand-600 bg-brand-50 px-2 py-0.5 rounded-full text-xs ml-2 font-bold">
                                     {log.food.servingSize || '1 serving'}
                                   </span>
                                 </div>
                                 <div className="text-xs text-slate-400">
                                   P: {log.food.protein}g • C: {log.food.carbs}g • F: {log.food.fat}g
                                   {log.food.micros?.['Fiber'] ? ` • Fiber: ${log.food.micros['Fiber']}g` : ''}
                                 </div>
                               </div>
                               <div className="font-bold text-slate-600">{log.food.calories}</div>
                            </div>
                          ))
                        )}
                        <button 
                          onClick={() => { setSelectedMeal(type); setIsAdding(true); }}
                          className="w-full p-3 text-sm font-bold text-brand-600 hover:bg-brand-50 transition-colors text-center"
                        >
                          + Add Food
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </>
          ) : (
            <div className="bg-white rounded-2xl shadow-lg border border-slate-100 p-6 animate-fade-in-up">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-slate-800">Add to {selectedMeal}</h3>
                <button onClick={() => setIsAdding(false)} className="text-slate-400 hover:text-slate-600">Cancel</button>
              </div>

              {/* AI Input */}
              <div className="mb-8">
                 <label className="block text-sm font-bold text-slate-700 mb-2">✨ Quick Add with AI (Any measure)</label>
                 <div className="flex gap-2">
                   <input 
                     type="text"
                     value={aiInput}
                     onChange={e => setAiInput(e.target.value)}
                     placeholder="e.g., 200g chicken, 1.5 cups rice, 3oz salmon, 1 tbsp olive oil"
                     className="flex-1 p-3 border-2 border-slate-200 rounded-xl focus:border-brand-500 focus:outline-none"
                     onKeyDown={e => e.key === 'Enter' && handleAiParse()}
                   />
                   <Button onClick={handleAiParse} disabled={isAiLoading || !aiInput}>
                     {isAiLoading ? '...' : 'Add'}
                   </Button>
                 </div>
                 <p className="text-xs text-slate-400 mt-2">
                   You can use grams (g), ounces (oz), cups, tablespoons, or any other unit.
                 </p>
              </div>

              <div className="border-t border-slate-100 pt-6">
                <label className="block text-sm font-bold text-slate-700 mb-2">Or choose from list</label>
                <input 
                  type="text" 
                  placeholder="Search foods..." 
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                  className="w-full p-3 border-2 border-slate-200 rounded-xl mb-4 focus:border-brand-500 focus:outline-none"
                />
                <div className="space-y-2 max-h-60 overflow-y-auto pr-2">
                  {MOCK_COMMON_FOODS.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase())).map(food => (
                     <div key={food.id} className="flex justify-between items-center p-3 border border-slate-100 rounded-lg hover:border-brand-300 cursor-pointer group" onClick={() => handleManualAdd(food)}>
                        <div>
                          <div className="font-bold text-slate-700 group-hover:text-brand-700">
                             {food.name}
                             <span className="ml-2 text-xs font-normal text-slate-400">({food.servingSize})</span>
                          </div>
                          <div className="text-xs text-slate-400">{food.calories} kcal</div>
                        </div>
                        <div className="w-6 h-6 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-colors">+</div>
                     </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'analysis' && (
        <div className="animate-fade-in space-y-8">
           {/* Macros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
             <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
               📊 Macro Targets
             </h3>
             <ProgressBar 
               label="Protein" 
               current={consumedMacros.protein} 
               target={targets.protein} 
               unit="g"
               colorClass="bg-blue-500" 
             />
             <ProgressBar 
               label="Carbohydrates" 
               current={consumedMacros.carbs} 
               target={targets.carbs} 
               unit="g"
               colorClass="bg-amber-400" 
             />
             <ProgressBar 
               label="Fats" 
               current={consumedMacros.fat} 
               target={targets.fat} 
               unit="g"
               colorClass="bg-rose-400" 
             />
             <ProgressBar 
               label="Fiber" 
               current={consumedMicros["Fiber"] || 0} 
               target={NUTRIENT_INFO["Fiber"].targetVal || 30} 
               unit="g"
               colorClass="bg-emerald-500" 
             />
             <ProgressBar 
               label="Sugar" 
               current={consumedMicros["Sugar"] || 0} 
               target={NUTRIENT_INFO["Sugar"].targetVal || 50} 
               unit="g"
               colorClass="bg-purple-400" 
             />
           </section>

           {/* Micros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-2">Micronutrient Breakdown</h3>
              <p className="text-sm text-slate-500 mb-6">Tap any nutrient to learn more about why you need it.</p>

              <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                 {/* Combine static list keys with consumed keys to ensure we show everything relevant.
                     We also explicitly filter out macros that are already shown above.
                  */}
                 {Array.from(new Set([...Object.keys(consumedMicros), ...Object.keys(NUTRIENT_INFO)])).filter(k => !['Protein','Carbohydrates','Fats','Fiber','Sugar'].includes(k)).map(key => {
                    const amount = consumedMicros[key] || 0;
                    const info = NUTRIENT_INFO[key];
                    const hasData = !!info;
                    const target = info?.targetVal;
                    const unit = info?.unit || '';

                    return (
                      <button 
                        key={key}
                        onClick={() => setSelectedNutrient(key)}
                        disabled={!hasData}
                        className={`p-4 rounded-xl border-2 text-left transition-all hover:scale-[1.02] active:scale-95 flex flex-col justify-between min-h-[100px]
                          ${hasData ? 'border-slate-100 hover:border-brand-300 bg-slate-50' : 'border-transparent opacity-50 cursor-default'}
                        `}
                      >
                         <div className="text-xs font-bold text-slate-400 uppercase mb-1 truncate w-full" title={key}>{key}</div>

                         <div>
                            <div className="text-lg font-black text-slate-800 flex items-baseline gap-0.5">
                              {amount > 0 ? Math.round(amount * 10) / 10 : '-'}
                              {unit && <span className="text-xs font-normal text-slate-500">{unit}</span>}
                            </div>

                            {target && amount > 0 && (
                                <div className={`text-xs font-bold mt-1 ${
                                    (amount / target) > 1.2 ? 'text-amber-500' : 
                                    (amount / target) > 0.8 ? 'text-green-500' : 'text-slate-400'
                                }`}>
                                    {Math.round((amount / target) * 100)}% DV
                                </div>
                            )}
                         </div>
                      </button>
                    )
                 })}
              </div>
           </section>

           <NutrientDetailModal />
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { UserProfile, CalculatedMetrics, WellnessPlan, GamificationState, ActivityLevel, Goal, MealLog, MealType, FoodItem } from './types';
import { generateWellnessPlan } from './services/geminiService';

const calculateMetrics = (profile: UserProfile): CalculatedMetrics => {
  // Mifflin-St Jeor Equation
  const s = profile.gender === 'Male' ? 5 : -161;
  const bmr = (10 * profile.weightKg) + (6.25 * profile.heightCm) - (5 * profile.age) + s;

  // Activity Multipliers
  let multiplier = 1.2;
  switch (profile.activityLevel) {
    case ActivityLevel.Light: multiplier = 1.375; break;
    case ActivityLevel.Moderate: multiplier = 1.55; break;
    case ActivityLevel.VeryActive: multiplier = 1.725; break;
    case ActivityLevel.ExtraActive: multiplier = 1.9; break;
  }

  let tdee = bmr * multiplier;

  // Goal Adjustments
  if (profile.goal === Goal.FatLoss) tdee -= 500;
  if (profile.goal === Goal.MuscleGain) tdee += 300;

  const heightM = profile.heightCm / 100;
  const bmi = profile.weightKg / (heightM * heightM);

  let bmiCategory = 'Normal';
  if (bmi < 18.5) bmiCategory = 'Underweight';
  else if (bmi >= 25 && bmi < 30) bmiCategory = 'Overweight';
  else if (bmi >= 30) bmiCategory = 'Obese';

  // Macro Calculation (Simplified)
  // Protein: High for muscle/fat loss
  let proteinPerKg = 1.6;
  if (profile.goal === Goal.MuscleGain || profile.goal === Goal.FatLoss) proteinPerKg = 2.0;

  const proteinGrams = Math.round(profile.weightKg * proteinPerKg);
  const fatGrams = Math.round((tdee * 0.25) / 9); // ~25% calories from fat
  const carbGrams = Math.round((tdee - (proteinGrams * 4) - (fatGrams * 9)) / 4);

  return { 
    bmi, 
    bmr, 
    tdee: Math.round(tdee), 
    bmiCategory,
    macros: {
      protein: proteinGrams,
      fat: fatGrams,
      carbs: carbGrams
    }
  };
};

const initialGamification: GamificationState = {
  xp: 0,
  level: 1,
  streak: 1,
  completedQuestIds: [],
  badges: []
};

const App: React.FC = () => {
  const [view, setView] = useState<'onboarding' | 'dashboard'>('onboarding');
  const [isLoading, setIsLoading] = useState(false);

  // Application State
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [metrics, setMetrics] = useState<CalculatedMetrics | null>(null);
  const [plan, setPlan] = useState<WellnessPlan | null>(null);
  const [gamification, setGamification] = useState<GamificationState>(initialGamification);
  const [foodLogs, setFoodLogs] = useState<MealLog[]>([]);

  const handleOnboardingComplete = async (userProfile: UserProfile) => {
    setIsLoading(true);
    setProfile(userProfile);

    // 1. Calculate basic physics locally (immediate feedback potential)
    const calculated = calculateMetrics(userProfile);
    setMetrics(calculated);

    // 2. AI Generation
    try {
      const generatedPlan = await generateWellnessPlan(userProfile);
      setPlan(generatedPlan);
      setView('dashboard');
    } catch (e) {
      alert("Failed to generate plan. Please check API Key configuration.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddFood = (type: MealType, food: FoodItem) => {
    const newLog: MealLog = {
      id: Date.now().toString(),
      type,
      food,
      timestamp: Date.now()
    };
    setFoodLogs(prev => [...prev, newLog]);
  };

  const handleUpdateLog = (updatedLog: MealLog) => {
    setFoodLogs(prev => prev.map(log => log.id === updatedLog.id ? updatedLog : log));
  };

  const handleDeleteLog = (logId: string) => {
    setFoodLogs(prev => prev.filter(log => log.id !== logId));
  };

  const handleReset = () => {
    setProfile(null);
    setMetrics(null);
    setPlan(null);
    setFoodLogs([]);
    setGamification(initialGamification);
    setView('onboarding');
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">

      {/* Navbar */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-brand-500 rounded-lg flex items-center justify-center text-white font-bold text-xl">
              V
            </div>
            <span className="font-extrabold text-xl tracking-tight text-slate-900">Vital<span className="text-brand-600">Quest</span></span>
          </div>
          {view === 'dashboard' && (
             <div className="text-sm font-semibold text-slate-500 hidden sm:block">
               {gamification.xp} XP
             </div>
          )}
        </div>
      </nav>

      <main className="flex-grow">
        {view === 'onboarding' && (
          <div className="py-12 px-4">
             <div className="text-center mb-10">
               <h1 className="text-4xl font-extrabold text-slate-900 mb-4">Your Wellness Journey Starts Here.</h1>
               <p className="text-lg text-slate-600 max-w-2xl mx-auto">
                 Get a personalized, evidence-based plan tailored to your body, goals, and lifestyle. 
                 No generic advice—just science and daily quests.
               </p>
             </div>
             <Onboarding onComplete={handleOnboardingComplete} isLoading={isLoading} />
          </div>
        )}

        {view === 'dashboard' && profile && metrics && plan && (
          <Dashboard 
            profile={profile}
            metrics={metrics}
            plan={plan}
            gamification={gamification}
            onUpdateGamification={setGamification}
            onReset={handleReset}
            foodLogs={foodLogs}
            onAddFood={handleAddFood}
            onUpdateLog={handleUpdateLog}
            onDeleteLog={handleDeleteLog}
          />
        )}
      </main>

    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { CalculatedMetrics, GamificationState, UserProfile, WellnessPlan, Habit, MealLog, MealType, FoodItem } from '../types';
import { PlanDisplay } from './PlanDisplay';
import { Button } from './ui/Button';
import { NutritionTracker } from './NutritionTracker';

interface DashboardProps {
  profile: UserProfile;
  metrics: CalculatedMetrics;
  plan: WellnessPlan;
  gamification: GamificationState;
  onUpdateGamification: (newState: GamificationState) => void;
  onReset: () => void;
  // New props for food logging handled in App container for now
  foodLogs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  onUpdateLog: (log: MealLog) => void;
  onDeleteLog: (logId: string) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  profile, 
  metrics, 
  plan, 
  gamification, 
  onUpdateGamification,
  onReset,
  foodLogs,
  onAddFood,
  onUpdateLog,
  onDeleteLog
}) => {
  const [activeTab, setActiveTab] = useState<'plan' | 'quests' | 'nutrition'>('plan');

  const completeQuest = (questId: string, xpReward: number) => {
    if (gamification.completedQuestIds.includes(questId)) return;

    // Play sound or confetti effect here in a full app
    const newXp = gamification.xp + xpReward;
    const newLevel = Math.floor(newXp / 100) + 1;

    onUpdateGamification({
      ...gamification,
      xp: newXp,
      level: newLevel,
      completedQuestIds: [...gamification.completedQuestIds, questId]
    });
  };

  const calculateProgress = () => {
    const total = plan.dailyQuests.length;
    const completed = gamification.completedQuestIds.length;
    return total === 0 ? 0 : Math.round((completed / total) * 100);
  };

  // Calculate consumed for header
  const caloriesConsumed = foodLogs.reduce((acc, l) => acc + l.food.calories, 0);

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-6 pb-20">

      {/* Gamification Header */}
      <header className="flex flex-col md:flex-row justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-slate-100 mb-6 gap-4">
        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="w-12 h-12 bg-amber-100 rounded-full flex items-center justify-center text-2xl shadow-inner">
            ⚡
          </div>
          <div>
            <h2 className="font-bold text-slate-800 text-lg">Level {gamification.level}</h2>
            <div className="w-32 h-2 bg-slate-100 rounded-full mt-1 overflow-hidden">
              <div 
                className="h-full bg-amber-400 transition-all duration-500" 
                style={{ width: `${gamification.xp % 100}%` }} 
              />
            </div>
            <p className="text-xs text-slate-500 mt-1">{gamification.xp % 100} / 100 XP to next level</p>
          </div>
        </div>

        <div className="flex gap-6 text-center">
            <div>
                <span className="block text-xl font-black text-brand-600">{gamification.streak} 🔥</span>
                <span className="text-xs font-bold text-slate-400 uppercase">Day Streak</span>
            </div>
             <div>
                <span className="block text-xl font-black text-slate-800">
                  {caloriesConsumed} <span className="text-slate-400 font-normal text-sm">/ {Math.round(metrics.tdee)}</span>
                </span>
                <span className="text-xs font-bold text-slate-400 uppercase">Kcal Eaten</span>
            </div>
        </div>
      </header>

      {/* Tabs */}
      <div className="flex gap-2 mb-6 bg-slate-100 p-1 rounded-xl w-fit mx-auto md:mx-0 overflow-x-auto">
        <button 
          onClick={() => setActiveTab('plan')}
          className={`px-6 py-2 rounded-lg font-bold text-sm transition-all whitespace-nowrap ${activeTab === 'plan' ? 'bg-white shadow text-brand-600' : 'text-slate-500 hover:text-slate-700'}`}
        >
          My Plan
        </button>
        <button 
          onClick={() => setActiveTab('nutrition')}
          className={`px-6 py-2 rounded-lg font-bold text-sm transition-all whitespace-nowrap ${activeTab === 'nutrition' ? 'bg-white shadow text-brand-600' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Nutrition & Logs
        </button>
        <button 
          onClick={() => setActiveTab('quests')}
          className={`px-6 py-2 rounded-lg font-bold text-sm transition-all whitespace-nowrap ${activeTab === 'quests' ? 'bg-white shadow text-brand-600' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Daily Quests
          {plan.dailyQuests.length - gamification.completedQuestIds.length > 0 && (
             <span className="ml-2 bg-red-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">
               {plan.dailyQuests.length - gamification.completedQuestIds.length}
             </span>
          )}
        </button>
      </div>

      {activeTab === 'plan' && <PlanDisplay plan={plan} />}

      {activeTab === 'nutrition' && (
        <NutritionTracker 
          logs={foodLogs} 
          onAddFood={onAddFood}
          onUpdateLog={onUpdateLog}
          onDeleteLog={onDeleteLog}
          targets={{
             calories: metrics.tdee,
             ...metrics.macros
          }}
        />
      )}

      {activeTab === 'quests' && (
        <div className="space-y-4 animate-fade-in">
          <div className="flex justify-between items-end mb-2">
            <h3 className="text-xl font-bold text-slate-800">Today's Goals</h3>
            <span className="text-sm font-semibold text-brand-600">{calculateProgress()}% Complete</span>
          </div>

          {/* Progress Bar */}
          <div className="h-4 bg-slate-200 rounded-full overflow-hidden mb-6">
             <div 
               className="h-full bg-brand-500 transition-all duration-1000 ease-out"
               style={{ width: `${calculateProgress()}%` }}
             />
          </div>

          <div className="grid gap-4">
            {plan.dailyQuests.map(quest => {
              const isCompleted = gamification.completedQuestIds.includes(quest.id);
              return (
                <div 
                  key={quest.id} 
                  onClick={() => !isCompleted && completeQuest(quest.id, quest.xpReward)}
                  className={`relative p-5 rounded-2xl border-2 transition-all cursor-pointer group
                    ${isCompleted 
                      ? 'bg-brand-50 border-brand-200 opacity-60' 
                      : 'bg-white border-slate-200 hover:border-brand-400 hover:shadow-md'
                    }`}
                >
                  <div className="flex items-start gap-4">
                    <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center text-white transition-colors
                      ${isCompleted ? 'bg-brand-500 border-brand-500' : 'border-slate-300 group-hover:border-brand-400'}`}>
                      {isCompleted && '✓'}
                    </div>
                    <div className="flex-1">
                      <h4 className={`font-bold text-lg ${isCompleted ? 'text-brand-800 line-through' : 'text-slate-800'}`}>{quest.title}</h4>
                      <p className="text-slate-500 text-sm">{quest.description}</p>
                    </div>
                    <div className="text-amber-500 font-bold text-sm bg-amber-50 px-2 py-1 rounded-lg">
                      +{quest.xpReward} XP
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {calculateProgress() === 100 && (
            <div className="mt-8 p-6 bg-gradient-to-r from-yellow-100 to-amber-100 rounded-2xl text-center border border-yellow-200 animate-bounce-slow">
              <div className="text-4xl mb-2">🎉</div>
              <h3 className="text-xl font-black text-yellow-800">All Quests Complete!</h3>
              <p className="text-yellow-700">You're crushing it! Come back tomorrow to keep the streak alive.</p>
            </div>
          )}
        </div>
      )}

      <div className="mt-12 text-center">
         <Button variant="ghost" onClick={onReset} className="text-slate-400 text-sm">Start Over (Debug)</Button>
      </div>

    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './ui/Button';
import { FoodItem, MealLog, MealType, MacroTargets } from '../types';
import { MOCK_COMMON_FOODS, NUTRIENT_INFO } from '../data/nutrientData';
import { parseFoodLog } from '../services/geminiService';

interface NutritionTrackerProps {
  logs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  onUpdateLog: (log: MealLog) => void;
  onDeleteLog: (logId: string) => void;
  targets: MacroTargets;
}

const MEAL_TYPES: MealType[] = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];

export const NutritionTracker: React.FC<NutritionTrackerProps> = ({ logs, onAddFood, onUpdateLog, onDeleteLog, targets }) => {
  const [activeTab, setActiveTab] = useState<'log' | 'analysis'>('log');
  const [isAdding, setIsAdding] = useState(false);
  const [selectedMeal, setSelectedMeal] = useState<MealType>('Breakfast');
  const [searchQuery, setSearchQuery] = useState('');
  const [aiInput, setAiInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedNutrient, setSelectedNutrient] = useState<string | null>(null);

  // Edit State
  const [editingLog, setEditingLog] = useState<MealLog | null>(null);

  // -- Derived Data --
  const consumedMacros = logs.reduce((acc, log) => ({
    calories: acc.calories + log.food.calories,
    protein: acc.protein + log.food.protein,
    carbs: acc.carbs + log.food.carbs,
    fat: acc.fat + log.food.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Consolidate micros
  const consumedMicros: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        consumedMicros[name] = (consumedMicros[name] || 0) + (amount as number);
      });
    }
  });

  // -- Handlers --
  const handleAiParse = async () => {
    if(!aiInput.trim()) return;
    setIsAiLoading(true);
    const foods = await parseFoodLog(aiInput);
    foods.forEach(f => onAddFood(selectedMeal, f));
    setIsAiLoading(false);
    setAiInput('');
    setIsAdding(false);
  };

  const handleManualAdd = (food: FoodItem) => {
    onAddFood(selectedMeal, food);
    setIsAdding(false);
  };

  const saveEditedLog = () => {
    if (editingLog) {
      onUpdateLog(editingLog);
      setEditingLog(null);
    }
  };

  const deleteLog = (id: string) => {
    if (window.confirm("Are you sure you want to delete this item?")) {
        onDeleteLog(id);
        setEditingLog(null); // Just in case it was being edited
    }
  };

  // -- Render Helpers --
  const ProgressBar = ({ current, target, colorClass, label, unit }: any) => {
    const pct = Math.min((current / target) * 100, 100);
    return (
      <div className="mb-4">
        <div className="flex justify-between text-sm font-bold text-slate-700 mb-1">
          <span>{label}</span>
          <span>{Math.round(current)} / {Math.round(target)}{unit}</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-500 ${colorClass}`} style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const NutrientDetailModal = () => {
    if (!selectedNutrient) return null;
    const info = NUTRIENT_INFO[selectedNutrient];
    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setSelectedNutrient(null)}>
        <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl" onClick={e => e.stopPropagation()}>
          <div className="flex justify-between items-start mb-4">
             <h3 className="text-2xl font-black text-slate-800">{selectedNutrient}</h3>
             <button onClick={() => setSelectedNutrient(null)} className="text-slate-400 hover:text-slate-800 text-xl font-bold">×</button>
          </div>

          {info ? (
            <div className="space-y-4">
              <p className="text-slate-600 leading-relaxed">{info.description}</p>

              <div className="flex justify-between items-center bg-slate-50 p-4 rounded-xl border border-slate-100">
                 <span className="font-bold text-slate-600">Daily Target</span>
                 <span className="font-black text-xl text-slate-800">{info.dailyValue}</span>
              </div>

              <div>
                <h4 className="font-bold text-sm text-brand-600 uppercase mb-2">Good Sources</h4>
                <div className="flex flex-wrap gap-2">
                  {info.sources.map(s => (
                    <span key={s} className="bg-brand-50 text-brand-800 px-3 py-1 rounded-full text-sm font-medium border border-brand-100">{s}</span>
                  ))}
                </div>
              </div>

              {info.caution && (
                <div className="bg-amber-50 p-4 rounded-xl border border-amber-100 text-amber-800 text-sm">
                  <strong>⚠️ Note: </strong> {info.caution}
                </div>
              )}
            </div>
          ) : (
            <p>No educational data available for this nutrient.</p>
          )}
        </div>
      </div>
    );
  };

  const EditLogModal = () => {
    if (!editingLog) return null;

    const updateField = (field: keyof FoodItem, val: string | number) => {
        setEditingLog(prev => {
            if (!prev) return null;
            return {
                ...prev,
                food: {
                    ...prev.food,
                    [field]: val
                }
            };
        });
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setEditingLog(null)}>
            <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl space-y-4" onClick={e => e.stopPropagation()}>
                <h3 className="text-xl font-bold text-slate-800">Edit Entry</h3>

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Food Name</label>
                    <input 
                        className="w-full p-2 border border-slate-200 rounded-lg"
                        value={editingLog.food.name}
                        onChange={e => updateField('name', e.target.value)}
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Serving Size</label>
                    <input 
                        className="w-full p-2 border border-slate-200 rounded-lg"
                        value={editingLog.food.servingSize || ''}
                        onChange={e => updateField('servingSize', e.target.value)}
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Calories</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.calories}
                            onChange={e => updateField('calories', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Protein (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.protein}
                            onChange={e => updateField('protein', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Carbs (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.carbs}
                            onChange={e => updateField('carbs', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Fat (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.fat}
                            onChange={e => updateField('fat', Number(e.target.value))}
                        />
                    </div>
                </div>

                <div className="flex gap-2 pt-2">
                    <Button variant="outline" fullWidth onClick={() => setEditingLog(null)}>Cancel</Button>
                    <Button variant="primary" fullWidth onClick={saveEditedLog}>Save</Button>
                </div>
            </div>
        </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Sub-tabs */}
      <div className="flex gap-2 bg-slate-100 p-1 rounded-xl w-fit">
        <button
          onClick={() => setActiveTab('log')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'log' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Food Log
        </button>
        <button
          onClick={() => setActiveTab('analysis')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Analysis & Info
        </button>
      </div>

      {activeTab === 'log' && (
        <div className="animate-fade-in">
          {!isAdding ? (
            <>
              {/* Daily Summary Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-6 flex justify-between items-center">
                <div>
                   <h3 className="font-bold text-slate-500 text-sm uppercase">Calories Remaining</h3>
                   <div className="text-4xl font-black text-slate-800">
                     {Math.max(0, Math.round(targets.calories - consumedMacros.calories))}
                   </div>
                </div>
                <div className="text-right">
                   <div className="text-sm text-slate-500">Eaten</div>
                   <div className="font-bold text-xl text-brand-600">{Math.round(consumedMacros.calories)} kcal</div>
                </div>
              </div>

              <div className="space-y-6">
                {MEAL_TYPES.map(type => {
                  const mealLogs = logs.filter(l => l.type === type);
                  const mealCals = mealLogs.reduce((acc, l) => acc + l.food.calories, 0);

                  return (
                    <div key={type} className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                      <div className="bg-slate-50 p-4 flex justify-between items-center border-b border-slate-100">
                        <h4 className="font-bold text-slate-800">{type}</h4>
                        <span className="text-sm font-medium text-slate-500">{mealCals} kcal</span>
                      </div>
                      <div className="divide-y divide-slate-100">
                        {mealLogs.length === 0 ? (
                          <div className="p-4 text-center text-slate-400 text-sm italic">No food logged</div>
                        ) : (
                          mealLogs.map(log => (
                            <div key={log.id} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors group">
                               <div className="flex-1">
                                 <div className="font-medium text-slate-800">
                                   {log.food.name} 
                                   <span className="text-brand-600 bg-brand-50 px-2 py-0.5 rounded-full text-xs ml-2 font-bold">
                                     {log.food.servingSize || '1 serving'}
                                   </span>
                                 </div>
                                 <div className="text-xs text-slate-400">
                                   P: {log.food.protein}g • C: {log.food.carbs}g • F: {log.food.fat}g
                                   {log.food.micros?.['Fiber'] ? ` • Fiber: ${log.food.micros['Fiber']}g` : ''}
                                 </div>
                               </div>
                               <div className="flex items-center gap-4">
                                   <div className="font-bold text-slate-600">{log.food.calories}</div>
                                   <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                       <button 
                                         onClick={() => setEditingLog(log)}
                                         className="p-1.5 text-slate-400 hover:text-brand-600 hover:bg-brand-50 rounded-lg"
                                         title="Edit"
                                       >
                                         <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>
                                       </button>
                                       <button 
                                         onClick={() => deleteLog(log.id)}
                                         className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                                         title="Delete"
                                       >
                                         <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                                       </button>
                                   </div>
                               </div>
                            </div>
                          ))
                        )}
                        <button 
                          onClick={() => { setSelectedMeal(type); setIsAdding(true); }}
                          className="w-full p-3 text-sm font-bold text-brand-600 hover:bg-brand-50 transition-colors text-center"
                        >
                          + Add Food
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </>
          ) : (
            <div className="bg-white rounded-2xl shadow-lg border border-slate-100 p-6 animate-fade-in-up">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-slate-800">Add to {selectedMeal}</h3>
                <button onClick={() => setIsAdding(false)} className="text-slate-400 hover:text-slate-600">Cancel</button>
              </div>

              {/* AI Input */}
              <div className="mb-8">
                 <label className="block text-sm font-bold text-slate-700 mb-2">✨ Quick Add with AI (Any measure)</label>
                 <div className="flex gap-2">
                   <input 
                     type="text"
                     value={aiInput}
                     onChange={e => setAiInput(e.target.value)}
                     placeholder="e.g., 200g chicken, 1.5 cups rice, 3oz salmon, 1 tbsp olive oil"
                     className="flex-1 p-3 border-2 border-slate-200 rounded-xl focus:border-brand-500 focus:outline-none"
                     onKeyDown={e => e.key === 'Enter' && handleAiParse()}
                   />
                   <Button onClick={handleAiParse} disabled={isAiLoading || !aiInput}>
                     {isAiLoading ? '...' : 'Add'}
                   </Button>
                 </div>
                 <p className="text-xs text-slate-400 mt-2">
                   You can use grams (g), ounces (oz), cups, tablespoons, or any other unit.
                 </p>
              </div>

              <div className="border-t border-slate-100 pt-6">
                <label className="block text-sm font-bold text-slate-700 mb-2">Or choose from list</label>
                <input 
                  type="text" 
                  placeholder="Search foods..." 
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                  className="w-full p-3 border-2 border-slate-200 rounded-xl mb-4 focus:border-brand-500 focus:outline-none"
                />
                <div className="space-y-2 max-h-60 overflow-y-auto pr-2">
                  {MOCK_COMMON_FOODS.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase())).map(food => (
                     <div key={food.id} className="flex justify-between items-center p-3 border border-slate-100 rounded-lg hover:border-brand-300 cursor-pointer group" onClick={() => handleManualAdd(food)}>
                        <div>
                          <div className="font-bold text-slate-700 group-hover:text-brand-700">
                             {food.name}
                             <span className="ml-2 text-xs font-normal text-slate-400">({food.servingSize})</span>
                          </div>
                          <div className="text-xs text-slate-400">{food.calories} kcal</div>
                        </div>
                        <div className="w-6 h-6 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-colors">+</div>
                     </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'analysis' && (
        <div className="animate-fade-in space-y-8">
           {/* Macros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
             <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
               📊 Macro Targets
             </h3>
             <ProgressBar 
               label="Protein" 
               current={consumedMacros.protein} 
               target={targets.protein} 
               unit="g"
               colorClass="bg-blue-500" 
             />
             <ProgressBar 
               label="Carbohydrates" 
               current={consumedMacros.carbs} 
               target={targets.carbs} 
               unit="g"
               colorClass="bg-amber-400" 
             />
             <ProgressBar 
               label="Fats" 
               current={consumedMacros.fat} 
               target={targets.fat} 
               unit="g"
               colorClass="bg-rose-400" 
             />
             <ProgressBar 
               label="Fiber" 
               current={consumedMicros["Fiber"] || 0} 
               target={NUTRIENT_INFO["Fiber"].targetVal || 30} 
               unit="g"
               colorClass="bg-emerald-500" 
             />
             <ProgressBar 
               label="Sugar" 
               current={consumedMicros["Sugar"] || 0} 
               target={NUTRIENT_INFO["Sugar"].targetVal || 50} 
               unit="g"
               colorClass="bg-purple-400" 
             />
           </section>

           {/* Micros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-2">Micronutrient Breakdown</h3>
              <p className="text-sm text-slate-500 mb-6">Tap any nutrient to learn more about why you need it.</p>

              <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                 {/* Combine static list keys with consumed keys to ensure we show everything relevant.
                     We also explicitly filter out macros that are already shown above.
                  */}
                 {Array.from(new Set([...Object.keys(consumedMicros), ...Object.keys(NUTRIENT_INFO)])).filter(k => !['Protein','Carbohydrates','Fats','Fiber','Sugar'].includes(k)).map(key => {
                    const amount = consumedMicros[key] || 0;
                    const info = NUTRIENT_INFO[key];
                    const hasData = !!info;
                    const target = info?.targetVal;
                    const unit = info?.unit || '';

                    return (
                      <button 
                        key={key}
                        onClick={() => setSelectedNutrient(key)}
                        disabled={!hasData}
                        className={`p-4 rounded-xl border-2 text-left transition-all hover:scale-[1.02] active:scale-95 flex flex-col justify-between min-h-[100px]
                          ${hasData ? 'border-slate-100 hover:border-brand-300 bg-slate-50' : 'border-transparent opacity-50 cursor-default'}
                        `}
                      >
                         <div className="text-xs font-bold text-slate-400 uppercase mb-1 truncate w-full" title={key}>{key}</div>

                         <div>
                            <div className="text-lg font-black text-slate-800 flex items-baseline gap-0.5">
                              {amount > 0 ? Math.round(amount * 10) / 10 : '-'}
                              {unit && <span className="text-xs font-normal text-slate-500">{unit}</span>}
                            </div>

                            {target && amount > 0 && (
                                <div className={`text-xs font-bold mt-1 ${
                                    (amount / target) > 1.2 ? 'text-amber-500' : 
                                    (amount / target) > 0.8 ? 'text-green-500' : 'text-slate-400'
                                }`}>
                                    {Math.round((amount / target) * 100)}% DV
                                </div>
                            )}
                         </div>
                      </button>
                    )
                 })}
              </div>
           </section>

           <NutrientDetailModal />
        </div>
      )}
      <EditLogModal />
    </div>
  );
};

import React, { useState } from 'react';
import { ActivityLevel, DietaryRestriction, Gender, Goal, UserProfile } from '../types';
import { Button } from './ui/Button';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
  isLoading: boolean;
}

const steps = [
  'Basics',
  'Body',
  'Lifestyle',
  'Medical'
];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete, isLoading }) => {
  const [step, setStep] = useState(0);
  const [profile, setProfile] = useState<Partial<UserProfile>>({
    dietaryRestrictions: [],
    gender: Gender.PreferNotToSay,
    activityLevel: ActivityLevel.Sedentary,
    goal: Goal.GeneralHealth
  });

  // Unit State
  const [heightUnit, setHeightUnit] = useState<'cm' | 'ft'>('cm');
  const [weightUnit, setWeightUnit] = useState<'kg' | 'lbs'>('kg');

  // Local state for imperial inputs to ensure smooth typing without rounding jitter
  const [feet, setFeet] = useState('');
  const [inches, setInches] = useState('');
  const [pounds, setPounds] = useState('');

  const handleNext = () => {
    if (step < steps.length - 1) {
      setStep(step + 1);
    } else {
      onComplete(profile as UserProfile);
    }
  };

  const handleBack = () => {
    if (step > 0) setStep(step - 1);
  };

  const updateProfile = (key: keyof UserProfile, value: any) => {
    setProfile(prev => ({ ...prev, [key]: value }));
  };

  const toggleRestriction = (r: DietaryRestriction) => {
    const current = profile.dietaryRestrictions || [];
    if (current.includes(r)) {
      updateProfile('dietaryRestrictions', current.filter(i => i !== r));
    } else {
      updateProfile('dietaryRestrictions', [...current, r]);
    }
  };

  // Imperial Handlers
  const handleImperialHeightChange = (f: string, i: string) => {
    setFeet(f);
    setInches(i);
    const ftVal = parseInt(f) || 0;
    const inVal = parseInt(i) || 0;
    if (ftVal > 0 || inVal > 0) {
      const totalInches = (ftVal * 12) + inVal;
      const cm = Math.round(totalInches * 2.54);
      updateProfile('heightCm', cm);
    } else {
        updateProfile('heightCm', undefined);
    }
  };

  const handlePoundsChange = (val: string) => {
    setPounds(val);
    const lbs = parseFloat(val);
    if (!isNaN(lbs)) {
       const kg = lbs * 0.453592;
       updateProfile('weightKg', parseFloat(kg.toFixed(1)));
    } else {
        updateProfile('weightKg', undefined);
    }
  };

  const handleUnitChange = (type: 'height' | 'weight', unit: string) => {
      if (type === 'height') {
          const newUnit = unit as 'cm' | 'ft';
          setHeightUnit(newUnit);
          // Convert existing value to populate inputs
          if (profile.heightCm && newUnit === 'ft') {
             const totalIn = profile.heightCm / 2.54;
             setFeet(Math.floor(totalIn / 12).toString());
             setInches(Math.round(totalIn % 12).toString());
          }
      } else {
          const newUnit = unit as 'kg' | 'lbs';
          setWeightUnit(newUnit);
          if (profile.weightKg && newUnit === 'lbs') {
              setPounds(Math.round(profile.weightKg * 2.20462).toString());
          }
      }
  };

  const renderStep = () => {
    switch (step) {
      case 0:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Let's start with the basics</h2>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Age</label>
              <input 
                type="number" 
                value={profile.age || ''} 
                onChange={e => updateProfile('age', parseInt(e.target.value))}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                placeholder="Years"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Gender</label>
              <div className="flex gap-2">
                {[Gender.Male, Gender.Female, Gender.PreferNotToSay].map(g => (
                  <button
                    key={g}
                    onClick={() => updateProfile('gender', g)}
                    className={`flex-1 py-3 rounded-xl border-2 font-medium transition-colors ${
                      profile.gender === g 
                        ? 'border-brand-500 bg-brand-50 text-brand-700' 
                        : 'border-slate-200 hover:border-brand-300'
                    }`}
                  >
                    {g === Gender.PreferNotToSay ? 'Other' : g}
                  </button>
                ))}
              </div>
            </div>
          </div>
        );
      case 1:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Body Metrics</h2>

            {/* Height Section */}
            <div>
              <div className="flex justify-between items-center mb-2">
                 <label className="block text-sm font-semibold text-slate-600">Height</label>
                 <div className="flex bg-slate-100 rounded-lg p-1">
                    <button 
                      onClick={() => handleUnitChange('height', 'cm')}
                      className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${heightUnit === 'cm' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                    >
                      CM
                    </button>
                    <button 
                      onClick={() => handleUnitChange('height', 'ft')}
                      className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${heightUnit === 'ft' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                    >
                      FT
                    </button>
                 </div>
              </div>

              {heightUnit === 'cm' ? (
                <input 
                  type="number" 
                  value={profile.heightCm || ''} 
                  onChange={e => updateProfile('heightCm', parseInt(e.target.value))}
                  className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                  placeholder="175"
                />
              ) : (
                <div className="flex gap-4">
                   <div className="flex-1">
                     <input 
                        type="number" 
                        value={feet} 
                        onChange={e => handleImperialHeightChange(e.target.value, inches)}
                        className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                        placeholder="5"
                      />
                      <span className="text-xs text-slate-400 mt-1 ml-1">Feet</span>
                   </div>
                   <div className="flex-1">
                     <input 
                        type="number" 
                        value={inches} 
                        onChange={e => handleImperialHeightChange(feet, e.target.value)}
                        className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                        placeholder="10"
                      />
                      <span className="text-xs text-slate-400 mt-1 ml-1">Inches</span>
                   </div>
                </div>
              )}
            </div>

            {/* Weight Section */}
            <div>
              <div className="flex justify-between items-center mb-2">
                 <label className="block text-sm font-semibold text-slate-600">Weight</label>
                 <div className="flex bg-slate-100 rounded-lg p-1">
                    <button 
                      onClick={() => handleUnitChange('weight', 'kg')}
                      className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${weightUnit === 'kg' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                    >
                      KG
                    </button>
                    <button 
                      onClick={() => handleUnitChange('weight', 'lbs')}
                      className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${weightUnit === 'lbs' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}
                    >
                      LBS
                    </button>
                 </div>
              </div>

              {weightUnit === 'kg' ? (
                <input 
                  type="number" 
                  value={profile.weightKg || ''} 
                  onChange={e => updateProfile('weightKg', parseFloat(e.target.value))}
                  className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                  placeholder="70"
                />
              ) : (
                <input 
                  type="number" 
                  value={pounds} 
                  onChange={e => handlePoundsChange(e.target.value)}
                  className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none text-lg"
                  placeholder="150"
                />
              )}
            </div>
          </div>
        );
      case 2:
        return (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Your Goals & Lifestyle</h2>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Main Goal</label>
              <select 
                value={profile.goal} 
                onChange={e => updateProfile('goal', e.target.value)}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none bg-white"
              >
                {Object.values(Goal).map(g => <option key={g} value={g}>{g}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Activity Level</label>
              <select 
                value={profile.activityLevel} 
                onChange={e => updateProfile('activityLevel', e.target.value)}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none bg-white"
              >
                {Object.values(ActivityLevel).map(a => <option key={a} value={a}>{a}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Sleep (Avg Hours)</label>
               <input 
                type="number" 
                value={profile.sleepHours || ''} 
                onChange={e => updateProfile('sleepHours', parseInt(e.target.value))}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none"
                placeholder="7"
              />
            </div>
          </div>
        );
      case 3:
        return (
           <div className="space-y-6 animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800">Final Safety Checks</h2>

            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">Dietary Restrictions</label>
              <div className="flex flex-wrap gap-2">
                {Object.values(DietaryRestriction).map(r => (
                  <button
                    key={r}
                    onClick={() => toggleRestriction(r)}
                    className={`px-4 py-2 rounded-full text-sm font-bold border-2 transition-colors ${
                      profile.dietaryRestrictions?.includes(r)
                        ? 'border-brand-500 bg-brand-100 text-brand-700'
                        : 'border-slate-200 text-slate-500 hover:border-brand-200'
                    }`}
                  >
                    {r}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-600 mb-2">
                Medical Conditions / Medications
                <span className="block text-xs font-normal text-slate-400">Optional. Enter "None" if healthy. If you are pregnant or have a chronic condition, please list it here so we can keep recommendations safe.</span>
              </label>
              <textarea 
                value={profile.medicationsOrConditions || ''} 
                onChange={e => updateProfile('medicationsOrConditions', e.target.value)}
                className="w-full p-4 rounded-xl border-2 border-slate-200 focus:border-brand-500 focus:outline-none"
                placeholder="e.g. Type 2 Diabetes, Pregnant, taking Blood Thinners..."
                rows={3}
              />
            </div>
          </div>
        );
      default: return null;
    }
  };

  const isStepValid = () => {
    if (step === 0) return profile.age && profile.age > 0;
    if (step === 1) return profile.heightCm && profile.weightKg;
    if (step === 2) return profile.goal && profile.activityLevel && profile.sleepHours;
    return true;
  };

  return (
    <div className="max-w-xl mx-auto p-6">
      {/* Progress Bar */}
      <div className="flex gap-2 mb-8">
        {steps.map((_, i) => (
          <div key={i} className={`h-2 flex-1 rounded-full transition-colors ${i <= step ? 'bg-brand-500' : 'bg-slate-200'}`} />
        ))}
      </div>

      <div className="bg-white rounded-3xl p-8 shadow-xl border border-slate-100 min-h-[400px] flex flex-col justify-between">
        {renderStep()}

        <div className="flex gap-4 mt-8 pt-6 border-t border-slate-100">
          {step > 0 && (
            <Button variant="ghost" onClick={handleBack} disabled={isLoading}>
              Back
            </Button>
          )}
          <Button 
            fullWidth 
            onClick={handleNext} 
            disabled={!isStepValid() || isLoading}
            variant="primary"
          >
            {isLoading ? 'Generating Plan...' : step === steps.length - 1 ? 'Create My Plan' : 'Next'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './ui/Button';
import { FoodItem, MealLog, MealType, MacroTargets } from '../types';
import { MOCK_COMMON_FOODS, NUTRIENT_INFO } from '../data/nutrientData';
import { parseFoodLog } from '../services/geminiService';

interface NutritionTrackerProps {
  logs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  onUpdateLog: (log: MealLog) => void;
  onDeleteLog: (logId: string) => void;
  targets: MacroTargets;
}

const MEAL_TYPES: MealType[] = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];

const PRIORITY_MICROS = [
  "Fiber", "Vitamin C", "Vitamin D", "Magnesium", "Potassium", 
  "Iron", "Calcium", "Vitamin B12", "Zinc", "Omega-3"
];

export const NutritionTracker: React.FC<NutritionTrackerProps> = ({ logs, onAddFood, onUpdateLog, onDeleteLog, targets }) => {
  const [activeTab, setActiveTab] = useState<'log' | 'analysis'>('log');
  const [isAdding, setIsAdding] = useState(false);
  const [selectedMeal, setSelectedMeal] = useState<MealType>('Breakfast');
  const [searchQuery, setSearchQuery] = useState('');
  const [aiInput, setAiInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedNutrient, setSelectedNutrient] = useState<string | null>(null);

  // Edit State
  const [editingLog, setEditingLog] = useState<MealLog | null>(null);

  // -- Derived Data --
  const consumedMacros = logs.reduce((acc, log) => ({
    calories: acc.calories + log.food.calories,
    protein: acc.protein + log.food.protein,
    carbs: acc.carbs + log.food.carbs,
    fat: acc.fat + log.food.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Consolidate micros
  const consumedMicros: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        consumedMicros[name] = (consumedMicros[name] || 0) + (amount as number);
      });
    }
  });

  const calculateMicroScore = () => {
    let totalRatio = 0;
    let count = 0;

    PRIORITY_MICROS.forEach(key => {
        const info = NUTRIENT_INFO[key];
        if (!info || !info.targetVal) return;

        const current = consumedMicros[key] || 0;
        // Cap at 1.0 (100%) so excess doesn't compensate for deficiency elsewhere
        const ratio = Math.min(current / info.targetVal, 1);
        totalRatio += ratio;
        count++;
    });

    return count === 0 ? 0 : Math.round((totalRatio / count) * 100);
  };

  const microScore = calculateMicroScore();

  // -- Handlers --
  const handleAiParse = async () => {
    if(!aiInput.trim()) return;
    setIsAiLoading(true);
    const foods = await parseFoodLog(aiInput);
    foods.forEach(f => onAddFood(selectedMeal, f));
    setIsAiLoading(false);
    setAiInput('');
    setIsAdding(false);
  };

  const handleManualAdd = (food: FoodItem) => {
    onAddFood(selectedMeal, food);
    setIsAdding(false);
  };

  const saveEditedLog = () => {
    if (editingLog) {
      onUpdateLog(editingLog);
      setEditingLog(null);
    }
  };

  const deleteLog = (id: string) => {
    if (window.confirm("Are you sure you want to delete this item?")) {
        onDeleteLog(id);
        setEditingLog(null); // Just in case it was being edited
    }
  };

  // -- Render Helpers --
  const ProgressBar = ({ current, target, colorClass, label, unit }: any) => {
    const pct = Math.min((current / target) * 100, 100);
    return (
      <div className="mb-4">
        <div className="flex justify-between text-sm font-bold text-slate-700 mb-1">
          <span>{label}</span>
          <span>{Math.round(current)} / {Math.round(target)}{unit}</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-500 ${colorClass}`} style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const NutrientDetailModal = () => {
    if (!selectedNutrient) return null;
    const info = NUTRIENT_INFO[selectedNutrient];
    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setSelectedNutrient(null)}>
        <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl" onClick={e => e.stopPropagation()}>
          <div className="flex justify-between items-start mb-4">
             <h3 className="text-2xl font-black text-slate-800">{selectedNutrient}</h3>
             <button onClick={() => setSelectedNutrient(null)} className="text-slate-400 hover:text-slate-800 text-xl font-bold">×</button>
          </div>

          {info ? (
            <div className="space-y-4">
              <p className="text-slate-600 leading-relaxed">{info.description}</p>

              <div className="flex justify-between items-center bg-slate-50 p-4 rounded-xl border border-slate-100">
                 <span className="font-bold text-slate-600">Daily Target</span>
                 <span className="font-black text-xl text-slate-800">{info.dailyValue}</span>
              </div>

              <div>
                <h4 className="font-bold text-sm text-brand-600 uppercase mb-2">Good Sources</h4>
                <div className="flex flex-wrap gap-2">
                  {info.sources.map(s => (
                    <span key={s} className="bg-brand-50 text-brand-800 px-3 py-1 rounded-full text-sm font-medium border border-brand-100">{s}</span>
                  ))}
                </div>
              </div>

              {info.caution && (
                <div className="bg-amber-50 p-4 rounded-xl border border-amber-100 text-amber-800 text-sm">
                  <strong>⚠️ Note: </strong> {info.caution}
                </div>
              )}
            </div>
          ) : (
            <p>No educational data available for this nutrient.</p>
          )}
        </div>
      </div>
    );
  };

  const EditLogModal = () => {
    if (!editingLog) return null;

    const updateField = (field: keyof FoodItem, val: string | number) => {
        setEditingLog(prev => {
            if (!prev) return null;
            return {
                ...prev,
                food: {
                    ...prev.food,
                    [field]: val
                }
            };
        });
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setEditingLog(null)}>
            <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl space-y-4" onClick={e => e.stopPropagation()}>
                <h3 className="text-xl font-bold text-slate-800">Edit Entry</h3>

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Food Name</label>
                    <input 
                        className="w-full p-2 border border-slate-200 rounded-lg"
                        value={editingLog.food.name}
                        onChange={e => updateField('name', e.target.value)}
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Serving Size</label>
                    <input 
                        className="w-full p-2 border border-slate-200 rounded-lg"
                        value={editingLog.food.servingSize || ''}
                        onChange={e => updateField('servingSize', e.target.value)}
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Calories</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.calories}
                            onChange={e => updateField('calories', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Protein (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.protein}
                            onChange={e => updateField('protein', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Carbs (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.carbs}
                            onChange={e => updateField('carbs', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Fat (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.fat}
                            onChange={e => updateField('fat', Number(e.target.value))}
                        />
                    </div>
                </div>

                <div className="flex gap-2 pt-2">
                    <Button variant="outline" fullWidth onClick={() => setEditingLog(null)}>Cancel</Button>
                    <Button variant="primary" fullWidth onClick={saveEditedLog}>Save</Button>
                </div>
            </div>
        </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Sub-tabs */}
      <div className="flex gap-2 bg-slate-100 p-1 rounded-xl w-fit">
        <button
          onClick={() => setActiveTab('log')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'log' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Food Log
        </button>
        <button
          onClick={() => setActiveTab('analysis')}
          className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
        >
          Analysis & Info
        </button>
      </div>

      {activeTab === 'log' && (
        <div className="animate-fade-in">
          {!isAdding ? (
            <>
              {/* Daily Summary Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-6 flex justify-between items-center">
                <div>
                   <h3 className="font-bold text-slate-500 text-sm uppercase">Calories Remaining</h3>
                   <div className="text-4xl font-black text-slate-800">
                     {Math.max(0, Math.round(targets.calories - consumedMacros.calories))}
                   </div>
                </div>
                <div className="text-right">
                   <div className="text-sm text-slate-500">Eaten</div>
                   <div className="font-bold text-xl text-brand-600">{Math.round(consumedMacros.calories)} kcal</div>
                </div>
              </div>

              <div className="space-y-6">
                {MEAL_TYPES.map(type => {
                  const mealLogs = logs.filter(l => l.type === type);
                  const mealCals = mealLogs.reduce((acc, l) => acc + l.food.calories, 0);

                  return (
                    <div key={type} className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                      <div className="bg-slate-50 p-4 flex justify-between items-center border-b border-slate-100">
                        <h4 className="font-bold text-slate-800">{type}</h4>
                        <span className="text-sm font-medium text-slate-500">{mealCals} kcal</span>
                      </div>
                      <div className="divide-y divide-slate-100">
                        {mealLogs.length === 0 ? (
                          <div className="p-4 text-center text-slate-400 text-sm italic">No food logged</div>
                        ) : (
                          mealLogs.map(log => (
                            <div key={log.id} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors group">
                               <div className="flex-1">
                                 <div className="font-medium text-slate-800">
                                   {log.food.name} 
