import { GoogleGenAI, Type, Schema } from "@google/genai";
import { UserProfile, WellnessPlan, FoodItem } from "../types";

// NOTE: In a production app, the API key should be proxy-ed through a backend.
// For this frontend-only demo, we use the env variable directly.
const API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: API_KEY });

// Helper for exponential backoff to handle rate limits (429)
const retryWithBackoff = async <T>(operation: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
  try {
    return await operation();
  } catch (error: any) {
    // Check for 429 or RESOURCE_EXHAUSTED
    const isRateLimit = error?.status === 429 || 
                        error?.code === 429 || 
                        error?.message?.includes('429') || 
                        error?.status === 'RESOURCE_EXHAUSTED';

    if (retries > 0 && isRateLimit) {
      console.warn(`Rate limit hit. Retrying in ${delay}ms...`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return retryWithBackoff(operation, retries - 1, delay * 2);
    }
    throw error;
  }
};

const wellnessPlanSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    summary: {
      type: Type.STRING,
      description: "A motivating, 2-sentence summary of the user's path forward.",
    },
    currentStrengths: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of 2-3 things the user is already doing well based on their profile (e.g. 'Good sleep schedule', 'Active lifestyle').",
    },
    areasForImprovement: {
