export const parseFoodLog = async (input: string): Promise<FoodItem[]> => {
  const prompt = `
    Analyze this food log text and break it down into items with precise nutrition data.
    Input: "${input}"

    CRITICAL RULES FOR ACCURACY:
    1. MATCHING: Match foods to USDA/NCCDB standard values. 
    2. SERVING SIZE: EXTRACT the 'servingSize' explicitly (e.g., "200g", "4oz"). If quantity is vague (e.g. "a steak"), use a standard medium serving (e.g. 6oz/170g) and label it.
    3. RATIOS: Ensure Protein/Fat/Carb ratios are accurate for the specific food type (e.g., Chicken Breast = High Protein/Low Fat, Ribeye = High Protein/High Fat).
    4. DENSITY: Use accurate caloric density (e.g. Oil ~9kcal/g, Carbs/Protein ~4kcal/g).

    MICRONUTRIENTS:
    - Include ESTIMATED values for ALL significant nutrients found in the food.
    - DO NOT omit trace minerals if the food is a known source (e.g., Brazil nuts -> Selenium, Oysters -> Zinc).
    - Nutrients to track: Fiber, Sugar, Omega-3, Calcium, Iron, Magnesium, Zinc, Copper, Sodium, Potassium, Phosphorus, Manganese, Selenium, Chromium, Molybdenum, Iodine, Vitamins A, C, D, E, K, B1, B2, B3, B5, B6, B7, B9, B12, Choline.

    UNITS (Strict):
    - g: Fiber, Omega-3, Sugar
    - mg: Calcium, Iron, Magnesium, Zinc, Sodium, Potassium, Phosphorus, Manganese, Copper, Vit C, B1, B2, B3, B5, B6, Choline, Vit E
    - mcg: Selenium, Chromium, Molybdenum, Iodine, Vit A, D, K, B12, Folate, Biotin

    Output strictly in JSON format.
  `;

  try {
     const response = await retryWithBackoff(async () => {
       return await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: foodParseSchema,
        },
      });
     });

    const text = response.text;
    if(!text) return [];

    const data = JSON.parse(text);
    return data.foods.map((f: any, i: number) => {
      // Transform micros array back to map for the app's data model
      const microsMap: Record<string, number> = {};
      if (Array.isArray(f.micros)) {
        f.micros.forEach((m: {name: string, amount: number}) => {
          const normalizedName = NUTRIENT_ALIASES[m.name] || m.name;
          microsMap[normalizedName] = m.amount;
        });
      }

      return {
        id: `ai-${Date.now()}-${i}`,
        name: f.name,
        servingSize: f.servingSize || "Standard Serving",
        calories: f.calories,
        protein: f.protein,
        carbs: f.carbs,
        fat: f.fat,
        micros: microsMap
      };
    });

  } catch (error) {
    console.error("Error parsing food", error);
    return [];
  }
}

