import React, { useState, useRef } from 'react';
import { Button } from './ui/Button';
import { FoodItem, MealLog, MealType, MacroTargets, MealSuggestion } from '../types';
import { MOCK_COMMON_FOODS, NUTRIENT_INFO } from '../data/nutrientData';
import { parseFoodLog, suggestMeals } from '../services/geminiService';
// @ts-ignore
import html2canvas from 'html2canvas';
// @ts-ignore
import { jsPDF } from 'jspdf';

interface NutritionTrackerProps {
  logs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  onUpdateLog: (log: MealLog) => void;
  onDeleteLog: (logId: string) => void;
  targets: MacroTargets;
}

const MEAL_TYPES: MealType[] = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];

const PRIORITY_MICROS = [
  "Fiber", "Vitamin C", "Vitamin D", "Magnesium", "Potassium", 
  "Iron", "Calcium", "Vitamin B12", "Zinc", "Omega-3"
];

export const NutritionTracker: React.FC<NutritionTrackerProps> = ({ logs, onAddFood, onUpdateLog, onDeleteLog, targets }) => {
  const [activeTab, setActiveTab] = useState<'log' | 'analysis'>('log');
  const [isAdding, setIsAdding] = useState(false);
  const [isAddingSunlight, setIsAddingSunlight] = useState(false);
  const [isMealBuilderOpen, setIsMealBuilderOpen] = useState(false);

  const [selectedMeal, setSelectedMeal] = useState<MealType>('Breakfast');
  const [searchQuery, setSearchQuery] = useState('');
  const [aiInput, setAiInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedNutrient, setSelectedNutrient] = useState<string | null>(null);

  // Export state
  const reportRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  // Edit State
  const [editingLog, setEditingLog] = useState<MealLog | null>(null);

  // -- Derived Data --
  const consumedMacros = logs.reduce((acc, log) => ({
    calories: acc.calories + log.food.calories,
    protein: acc.protein + log.food.protein,
    carbs: acc.carbs + log.food.carbs,
    fat: acc.fat + log.food.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Consolidate micros
  const consumedMicros: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        consumedMicros[name] = (consumedMicros[name] || 0) + (amount as number);
      });
    }
  });

  const calculateMicroScore = () => {
    let totalRatio = 0;
    let count = 0;

    PRIORITY_MICROS.forEach(key => {
        const info = NUTRIENT_INFO[key];
        if (!info || !info.targetVal) return;

        const current = consumedMicros[key] || 0;
        // Cap at 1.0 (100%) so excess doesn't compensate for deficiency elsewhere
        const ratio = Math.min(current / info.targetVal, 1);
        totalRatio += ratio;
        count++;
    });

    return count === 0 ? 0 : Math.round((totalRatio / count) * 100);
  };

  const microScore = calculateMicroScore();

  // -- Handlers --
  const handleAiParse = async () => {
    if(!aiInput.trim()) return;
    setIsAiLoading(true);
    const foods = await parseFoodLog(aiInput);
    foods.forEach(f => onAddFood(selectedMeal, f));
    setIsAiLoading(false);
    setAiInput('');
    setIsAdding(false);
  };

  const handleManualAdd = (food: FoodItem) => {
    onAddFood(selectedMeal, food);
    setIsAdding(false);
  };

  const saveEditedLog = () => {
    if (editingLog) {
      onUpdateLog(editingLog);
      setEditingLog(null);
    }
  };

  const deleteLog = (id: string) => {
    if (window.confirm("Are you sure you want to delete this item?")) {
        onDeleteLog(id);
        setEditingLog(null); // Just in case it was being edited
    }
  };

  const handleExport = async (type: 'png' | 'pdf') => {
    if (!reportRef.current) return;
    setIsExporting(true);

    try {
      // Small delay to ensure render
      await new Promise(resolve => setTimeout(resolve, 100));

      const canvas = await html2canvas(reportRef.current, {
        scale: 2, // Better resolution
        backgroundColor: '#ffffff',
        logging: false
      });

      if (type === 'png') {
        const image = canvas.toDataURL("image/png");
        const link = document.createElement('a');
        link.href = image;
        link.download = `VitalQuest-Report-${new Date().toISOString().split('T')[0]}.png`;
        link.click();
      } else {
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('p', 'mm', 'a4');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
        pdf.save(`VitalQuest-Report-${new Date().toISOString().split('T')[0]}.pdf`);
      }
    } catch (err) {
      console.error("Export failed", err);
      alert("Failed to export report.");
    } finally {
      setIsExporting(false);
    }
  };

  // -- Render Helpers --
  const ProgressBar = ({ current, target, colorClass, label, unit }: any) => {
    const pct = Math.min((current / target) * 100, 100);
    return (
      <div className="mb-4 break-inside-avoid">
        <div className="flex justify-between text-sm font-bold text-slate-700 mb-1">
          <span>{label}</span>
          <span>{Math.round(current)} / {Math.round(target)}{unit}</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-500 ${colorClass}`} style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const NutrientDetailModal = () => {
    if (!selectedNutrient) return null;
    const info = NUTRIENT_INFO[selectedNutrient];
