import React, { useState, useEffect } from 'react';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { UserProfile, CalculatedMetrics, WellnessPlan, GamificationState, ActivityLevel, Goal, MealLog, MealType, FoodItem } from './types';
import { generateWellnessPlan } from './services/geminiService';

const STORAGE_KEY = 'vitalquest_user_data_v1';

const calculateMetrics = (profile: UserProfile): CalculatedMetrics => {
  // Mifflin-St Jeor Equation
  const s = profile.gender === 'Male' ? 5 : -161;
  const bmr = (10 * profile.weightKg) + (6.25 * profile.heightCm) - (5 * profile.age) + s;

  // Activity Multipliers
  let multiplier = 1.2;

  // Refined Logic: Use Steps if provided as a more accurate proxy for NEAT + Activity
  if (profile.dailySteps && profile.dailySteps > 0) {
      const steps = profile.dailySteps;
      if (steps < 5000) multiplier = 1.2;
      else if (steps < 7500) multiplier = 1.375;
      else if (steps < 10000) multiplier = 1.55;
      else if (steps < 15000) multiplier = 1.725;
      else multiplier = 1.9;
  } else {
    // Fallback to standard selection
    switch (profile.activityLevel) {
        case ActivityLevel.Light: multiplier = 1.375; break;
        case ActivityLevel.Moderate: multiplier = 1.55; break;
        case ActivityLevel.VeryActive: multiplier = 1.725; break;
        case ActivityLevel.ExtraActive: multiplier = 1.9; break;
        default: multiplier = 1.2;
    }
  }

  let tdee = bmr * multiplier;

  // Goal Adjustments
  if (profile.goal === Goal.FatLoss) tdee -= 500;
  if (profile.goal === Goal.MuscleGain) tdee += 300;

  const heightM = profile.heightCm / 100;
  const bmi = profile.weightKg / (heightM * heightM);

  let bmiCategory = 'Normal';
  if (bmi < 18.5) bmiCategory = 'Underweight';
  else if (bmi >= 25 && bmi < 30) bmiCategory = 'Overweight';
  else if (bmi >= 30) bmiCategory = 'Obese';

  // Macro Calculation (Simplified)
  // Protein: High for muscle/fat loss
  let proteinPerKg = 1.6;
  if (profile.goal === Goal.MuscleGain || profile.goal === Goal.FatLoss) proteinPerKg = 2.0;

  const proteinGrams = Math.round(profile.weightKg * proteinPerKg);
  const fatGrams = Math.round((tdee * 0.25) / 9); // ~25% calories from fat
  const carbGrams = Math.round((tdee - (proteinGrams * 4) - (fatGrams * 9)) / 4);

  return { 
    bmi, 
    bmr, 
    tdee: Math.round(tdee), 
    bmiCategory,
    macros: {
      protein: proteinGrams,
      fat: fatGrams,
      carbs: carbGrams
    }
  };
};

const initialGamification: GamificationState = {
  xp: 0,
  level: 1,
  streak: 1,
  completedQuestIds: [],
  badges: []
};

const App: React.FC = () => {
  const [view, setView] = useState<'onboarding' | 'dashboard'>('onboarding');
  const [isLoading, setIsLoading] = useState(false);

  // Application State
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [metrics, setMetrics] = useState<CalculatedMetrics | null>(null);
  const [plan, setPlan] = useState<WellnessPlan | null>(null);
  const [gamification, setGamification] = useState<GamificationState>(initialGamification);
  const [foodLogs, setFoodLogs] = useState<MealLog[]>([]);

  // Load from LocalStorage on mount
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        if (parsed.profile) {
          setProfile(parsed.profile);
          setMetrics(parsed.metrics);
          setPlan(parsed.plan);
          setGamification(parsed.gamification || initialGamification);
          setFoodLogs(parsed.foodLogs || []);
          setView('dashboard');
        }
      } catch (e) {
        console.error("Failed to parse saved user data", e);
      }
    }
  }, []);

  // Save to LocalStorage on updates
  useEffect(() => {
    // Only save if we have a valid profile. 
    // This prevents saving an empty state during the reset process.
    if (profile && metrics && plan) {
      const dataToSave = {
        profile,
        metrics,
        plan,
        gamification,
        foodLogs
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
    }
  }, [profile, metrics, plan, gamification, foodLogs]);

  const handleOnboardingComplete = async (userProfile: UserProfile) => {
    setIsLoading(true);
    setProfile(userProfile);

    // 1. Calculate basic physics locally (immediate feedback potential)
    const calculated = calculateMetrics(userProfile);
    setMetrics(calculated);

    // 2. AI Generation
    try {
      const generatedPlan = await generateWellnessPlan(userProfile);
      setPlan(generatedPlan);
      setView('dashboard');
    } catch (e) {
      alert("Failed to generate plan. Please check API Key configuration.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddFood = (type: MealType, food: FoodItem) => {
    // Generate a truly unique ID to prevent collisions during batch adds (e.g. AI parsing)
    const uniqueId = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const newLog: MealLog = {
      id: uniqueId,
      type,
      food,
      timestamp: Date.now()
    };
    setFoodLogs(prev => [...prev, newLog]);
  };

  const handleUpdateLog = (updatedLog: MealLog) => {
    setFoodLogs(prev => prev.map(log => log.id === updatedLog.id ? updatedLog : log));
  };

  const handleDeleteLog = (logId: string) => {
    setFoodLogs(prev => prev.filter(log => log.id !== logId));
  };

  const handleReset = () => {
    if (window.confirm("Are you sure you want to reset your profile? All progress and logs will be lost.")) {
      // 1. Clear Local Storage
      localStorage.removeItem(STORAGE_KEY);

      // 2. Explicitly clear state to update UI immediately and prevent re-saving
      setProfile(null);
      setMetrics(null);
      setPlan(null);
      setFoodLogs([]);
      setGamification(initialGamification);
      setView('onboarding');

      // 3. Force reload as a failsafe
      setTimeout(() => window.location.reload(), 100);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">

      {/* Navbar */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-brand-500 rounded-lg flex items-center justify-center text-white font-bold text-xl">
              V
            </div>
            <span className="font-extrabold text-xl tracking-tight text-slate-900">Vital<span className="text-brand-600">Quest</span></span>
          </div>
          {view === 'dashboard' && (
             <div className="text-sm font-semibold text-slate-500 hidden sm:block">
               {gamification.xp} XP
             </div>
          )}
        </div>
      </nav>

      <main className="flex-grow">
        {view === 'onboarding' && (
          <div className="py-12 px-4">
             <div className="text-center mb-10">
               <h1 className="text-4xl font-extrabold text-slate-900 mb-4">Your Wellness Journey Starts Here.</h1>
               <p className="text-lg text-slate-600 max-w-2xl mx-auto">
                 Get a personalized, evidence-based plan tailored to your body, goals, and lifestyle. 
                 No generic advice—just science and daily quests.
               </p>
             </div>
             <Onboarding onComplete={handleOnboardingComplete} isLoading={isLoading} />
          </div>
        )}

        {view === 'dashboard' && profile && metrics && plan && (
          <Dashboard 
            profile={profile}
            metrics={metrics}
            plan={plan}
            gamification={gamification}
            onUpdateGamification={setGamification}
            onReset={handleReset}
            foodLogs={foodLogs}
            onAddFood={handleAddFood}
            onUpdateLog={handleUpdateLog}
            onDeleteLog={handleDeleteLog}
          />
        )}
      </main>

    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Button } from './ui/Button';
import { FoodItem, MealLog, MealType, MacroTargets, MealSuggestion } from '../types';
import { MOCK_COMMON_FOODS, NUTRIENT_INFO } from '../data/nutrientData';
import { parseFoodLog, suggestMeals } from '../services/geminiService';
// @ts-ignore
import html2canvas from 'html2canvas';
// @ts-ignore
import { jsPDF } from 'jspdf';

interface NutritionTrackerProps {
  logs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  onUpdateLog: (log: MealLog) => void;
  onDeleteLog: (logId: string) => void;
  targets: MacroTargets;
}

const MEAL_TYPES: MealType[] = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];

const PRIORITY_MICROS = [
  "Fiber", "Vitamin C", "Vitamin D", "Magnesium", "Potassium", 
  "Iron", "Calcium", "Vitamin B12", "Zinc", "Omega-3"
];

export const NutritionTracker: React.FC<NutritionTrackerProps> = ({ logs, onAddFood, onUpdateLog, onDeleteLog, targets }) => {
  const [activeTab, setActiveTab] = useState<'log' | 'analysis'>('log');
  const [isAdding, setIsAdding] = useState(false);
  const [isAddingSunlight, setIsAddingSunlight] = useState(false);
  const [isMealBuilderOpen, setIsMealBuilderOpen] = useState(false);

  const [selectedMeal, setSelectedMeal] = useState<MealType>('Breakfast');
  const [searchQuery, setSearchQuery] = useState('');
  const [aiInput, setAiInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedNutrient, setSelectedNutrient] = useState<string | null>(null);

  // Export state
  const reportRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  // Edit State
  const [editingLog, setEditingLog] = useState<MealLog | null>(null);

  // -- Derived Data --
  const consumedMacros = logs.reduce((acc, log) => ({
    calories: acc.calories + log.food.calories,
    protein: acc.protein + log.food.protein,
    carbs: acc.carbs + log.food.carbs,
    fat: acc.fat + log.food.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Consolidate micros
  const consumedMicros: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        consumedMicros[name] = (consumedMicros[name] || 0) + (amount as number);
      });
    }
  });

  const calculateMicroScore = () => {
    let totalRatio = 0;
    let count = 0;

    PRIORITY_MICROS.forEach(key => {
        const info = NUTRIENT_INFO[key];
        if (!info || !info.targetVal) return;

        const current = consumedMicros[key] || 0;
        // Cap at 1.0 (100%) so excess doesn't compensate for deficiency elsewhere
        const ratio = Math.min(current / info.targetVal, 1);
        totalRatio += ratio;
        count++;
    });

    return count === 0 ? 0 : Math.round((totalRatio / count) * 100);
  };

  const microScore = calculateMicroScore();

  // -- Handlers --
  const handleAiParse = async () => {
    if(!aiInput.trim()) return;
    setIsAiLoading(true);
    const foods = await parseFoodLog(aiInput);
    foods.forEach(f => onAddFood(selectedMeal, f));
    setIsAiLoading(false);
    setAiInput('');
    setIsAdding(false);
  };

  const handleManualAdd = (food: FoodItem) => {
    onAddFood(selectedMeal, food);
    setIsAdding(false);
  };

  const saveEditedLog = () => {
    if (editingLog) {
      onUpdateLog(editingLog);
      setEditingLog(null);
    }
  };

  const deleteLog = (id: string) => {
    if (window.confirm("Are you sure you want to delete this item?")) {
        onDeleteLog(id);
        setEditingLog(null); // Just in case it was being edited
    }
  };

  const handleExport = async (type: 'png' | 'pdf') => {
    if (!reportRef.current) return;
    setIsExporting(true);

    try {
      // Small delay to ensure render
      await new Promise(resolve => setTimeout(resolve, 100));

      const canvas = await html2canvas(reportRef.current, {
        scale: 2, // Better resolution
        backgroundColor: '#ffffff',
        logging: false
      });

      if (type === 'png') {
        const image = canvas.toDataURL("image/png");
        const link = document.createElement('a');
        link.href = image;
        link.download = `VitalQuest-Report-${new Date().toISOString().split('T')[0]}.png`;
        link.click();
      } else {
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('p', 'mm', 'a4');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
        pdf.save(`VitalQuest-Report-${new Date().toISOString().split('T')[0]}.pdf`);
      }
    } catch (err) {
      console.error("Export failed", err);
      alert("Failed to export report.");
    } finally {
      setIsExporting(false);
    }
  };

  // -- Render Helpers --
  const ProgressBar = ({ current, target, colorClass, label, unit }: any) => {
    const pct = Math.min((current / target) * 100, 100);
    return (
      <div className="mb-4 break-inside-avoid">
        <div className="flex justify-between text-sm font-bold text-slate-700 mb-1">
          <span>{label}</span>
          <span>{Math.round(current)} / {Math.round(target)}{unit}</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-500 ${colorClass}`} style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const NutrientDetailModal = () => {
    if (!selectedNutrient) return null;
    const info = NUTRIENT_INFO[selectedNutrient];
    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setSelectedNutrient(null)}>
        <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl" onClick={e => e.stopPropagation()}>
          <div className="flex justify-between items-start mb-4">
             <h3 className="text-2xl font-black text-slate-800">{selectedNutrient}</h3>
             <button onClick={() => setSelectedNutrient(null)} className="text-slate-400 hover:text-slate-800 text-xl font-bold">×</button>
          </div>

          {info ? (
            <div className="space-y-4">
              <p className="text-slate-600 leading-relaxed">{info.description}</p>

              <div className="flex justify-between items-center bg-slate-50 p-4 rounded-xl border border-slate-100">
                 <span className="font-bold text-slate-600">Daily Target</span>
                 <span className="font-black text-xl text-slate-800">{info.dailyValue}</span>
              </div>

              <div>
                <h4 className="font-bold text-sm text-brand-600 uppercase mb-2">Good Sources</h4>
                <div className="flex flex-wrap gap-2">
                  {info.sources.map(s => (
                    <span key={s} className="bg-brand-50 text-brand-800 px-3 py-1 rounded-full text-sm font-medium border border-brand-100">{s}</span>
                  ))}
                </div>
              </div>

              {info.caution && (
                <div className="bg-amber-50 p-4 rounded-xl border border-amber-100 text-amber-800 text-sm">
                  <strong>⚠️ Note: </strong> {info.caution}
                </div>
              )}
            </div>
          ) : (
            <p>No educational data available for this nutrient.</p>
          )}
        </div>
      </div>
    );
  };

  const SunlightModal = () => {
    if (!isAddingSunlight) return null;
    const [mins, setMins] = useState('');

    const handleSave = () => {
        const val = parseInt(mins);
        if (val > 0) {
             // Estimate: ~20mcg (800 IU) for 30 mins of exposure
             // This is a rough average for midday sun.
             const vitD = Math.round(val * 0.7); 

             const sunItem: FoodItem = {
                 id: `sun-${Date.now()}`,
                 name: '☀️ Sunlight Exposure',
                 servingSize: `${val} mins`,
                 calories: 0,
                 protein: 0,
                 carbs: 0,
                 fat: 0,
                 micros: { "Vitamin D": vitD }
             };
             onAddFood('Snack', sunItem);
             setIsAddingSunlight(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setIsAddingSunlight(false)}>
            <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl space-y-4" onClick={e => e.stopPropagation()}>
                 <div className="flex justify-between items-center">
                    <h3 className="text-xl font-bold text-slate-800">☀️ Log Sunlight</h3>
                    <button onClick={() => setIsAddingSunlight(false)} className="text-slate-400 hover:text-slate-600">×</button>
                 </div>
                 <p className="text-sm text-slate-500">
                    Sun exposure helps your body produce Vitamin D. 
                    <br/><span className="text-xs text-slate-400 mt-1 block">*Estimation varies by skin tone, location, and time of day.</span>
                 </p>

                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Duration (Minutes)</label>
                    <input 
                        type="number"
                        autoFocus
                        className="w-full p-3 border-2 border-slate-200 rounded-xl focus:border-amber-400 focus:outline-none text-lg font-bold text-slate-800"
                        placeholder="e.g. 15"
                        value={mins}
                        onChange={e => setMins(e.target.value)}
                        onKeyDown={e => e.key === 'Enter' && handleSave()}
                    />
                 </div>

                 <Button variant="primary" className="bg-amber-500 hover:bg-amber-600 border-amber-700 shadow-amber-500/30" fullWidth onClick={handleSave}>
                    Add Vitamin D
                 </Button>
            </div>
        </div>
    );
  };

  const SmartMealBuilderModal = () => {
    if (!isMealBuilderOpen) return null;
    const [criteria, setCriteria] = useState('');
    const [suggestions, setSuggestions] = useState<MealSuggestion[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [targetMeal, setTargetMeal] = useState<MealType>('Lunch');

    const handleGenerate = async () => {
        if (!criteria.trim()) return;
        setIsLoading(true);
        const results = await suggestMeals(criteria);
        setSuggestions(results);
        setIsLoading(false);
    };

    const handleAddSuggestion = (s: MealSuggestion) => {
        const item: FoodItem = {
            id: `suggestion-${Date.now()}`,
            name: s.name,
            servingSize: "1 Meal",
            calories: s.calories,
            protein: s.protein,
            carbs: s.carbs,
            fat: s.fat,
            micros: s.micros
        };
        onAddFood(targetMeal, item);
        setIsMealBuilderOpen(false); // Close modal on add
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setIsMealBuilderOpen(false)}>
            <div className="bg-white rounded-3xl p-6 max-w-2xl w-full shadow-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-6">
                    <div>
                      <h3 className="text-2xl font-black text-slate-800 flex items-center gap-2">
                        ✨ Smart Meal Builder
                      </h3>
                      <p className="text-slate-500 text-sm">Food-first recommendations tailored to your goals.</p>
                    </div>
                    <button onClick={() => setIsMealBuilderOpen(false)} className="text-slate-400 hover:text-slate-800 text-2xl font-bold">×</button>
                </div>

                <div className="mb-6">
                    <label className="block text-sm font-bold text-slate-700 mb-2">Describe what you need</label>
                    <textarea 
                        className="w-full p-4 border-2 border-slate-200 rounded-xl focus:border-brand-500 focus:outline-none text-slate-800 mb-3"
                        placeholder="e.g., 'A high protein vegan breakfast under 400 calories', or 'Gluten-free dinner with lots of iron'."
                        rows={2}
                        value={criteria}
                        onChange={e => setCriteria(e.target.value)}
                    />

                    <div className="flex gap-4 items-center">
                       <select 
                         value={targetMeal}
                         onChange={e => setTargetMeal(e.target.value as MealType)}
                         className="p-3 border-2 border-slate-200 rounded-xl font-medium bg-white"
                       >
                           {MEAL_TYPES.map(t => <option key={t} value={t}>Plan for {t}</option>)}
                       </select>
                       <Button 
                         onClick={handleGenerate} 
                         disabled={isLoading || !criteria}
                         className="flex-1"
                       >
                         {isLoading ? 'Thinking...' : 'Generate Ideas'}
                       </Button>
                    </div>
                </div>

                {suggestions.length > 0 && (
                    <div className="space-y-4 animate-fade-in-up">
                        <h4 className="font-bold text-slate-400 uppercase text-xs tracking-wider">Suggestions</h4>
                        <div className="grid gap-4">
                            {suggestions.map((s, idx) => (
                                <div key={idx} className="border border-slate-200 rounded-2xl p-5 hover:border-brand-300 transition-colors bg-slate-50">
                                    <div className="flex justify-between items-start mb-2">
                                        <h5 className="font-bold text-xl text-brand-800">{s.name}</h5>
                                        <Button variant="outline" className="!py-1 !px-3 text-xs" onClick={() => handleAddSuggestion(s)}>
                                            Add to Log
                                        </Button>
                                    </div>
                                    <p className="text-slate-600 text-sm mb-3">{s.description}</p>

                                    <div className="bg-white p-3 rounded-xl border border-slate-100 mb-3">
                                        <div className="text-xs font-bold text-slate-500 uppercase mb-1">Why this fits</div>
                                        <p className="text-sm text-slate-700 italic">"{s.rationale}"</p>
                                    </div>

                                    <div className="mb-3">
                                        <div className="text-xs font-bold text-slate-500 uppercase mb-1">Ingredients</div>
                                        <div className="flex flex-wrap gap-1">
                                            {s.ingredients.map((ing, i) => (
                                                <span key={i} className="text-xs bg-slate-200 text-slate-600 px-2 py-1 rounded-md">{ing}</span>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="flex gap-3 text-sm">
                                        <span className="font-bold text-slate-800">{s.calories} kcal</span>
                                        <span className="text-slate-500">P: <span className="font-semibold text-slate-700">{s.protein}g</span></span>
                                        <span className="text-slate-500">C: <span className="font-semibold text-slate-700">{s.carbs}g</span></span>
                                        <span className="text-slate-500">F: <span className="font-semibold text-slate-700">{s.fat}g</span></span>
                                    </div>
                                    <div className="text-[10px] text-slate-400 mt-2 text-right">
                                       * Estimates based on standard portions.
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
  };

  const EditLogModal = () => {
    if (!editingLog) return null;

    const updateField = (field: keyof FoodItem, val: string | number) => {
        setEditingLog(prev => {
            if (!prev) return null;
            return {
                ...prev,
                food: {
                    ...prev.food,
                    [field]: val
                }
            };
        });
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setEditingLog(null)}>
            <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl space-y-4" onClick={e => e.stopPropagation()}>
                <h3 className="text-xl font-bold text-slate-800">Edit Entry</h3>

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Food Name</label>
                    <input 
                        className="w-full p-2 border border-slate-200 rounded-lg"
                        value={editingLog.food.name}
                        onChange={e => updateField('name', e.target.value)}
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Serving Size</label>
                    <input 
                        className="w-full p-2 border border-slate-200 rounded-lg"
                        value={editingLog.food.servingSize || ''}
                        onChange={e => updateField('servingSize', e.target.value)}
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Calories</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.calories}
                            onChange={e => updateField('calories', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Protein (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.protein}
                            onChange={e => updateField('protein', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Carbs (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.carbs}
                            onChange={e => updateField('carbs', Number(e.target.value))}
                        />
                    </div>
                     <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Fat (g)</label>
                        <input 
                            type="number"
                            className="w-full p-2 border border-slate-200 rounded-lg"
                            value={editingLog.food.fat}
                            onChange={e => updateField('fat', Number(e.target.value))}
                        />
                    </div>
                </div>

                <div className="flex gap-2 pt-2">
                    <Button variant="outline" fullWidth onClick={() => setEditingLog(null)}>Cancel</Button>
                    <Button variant="primary" fullWidth onClick={saveEditedLog}>Save</Button>
                </div>
            </div>
        </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Sub-tabs */}
      <div className="flex justify-between items-center">
        <div className="flex gap-2 bg-slate-100 p-1 rounded-xl w-fit">
            <button
            onClick={() => setActiveTab('log')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'log' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
            >
            Food Log
            </button>
            <button
            onClick={() => setActiveTab('analysis')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}
            >
            Analysis & Info
            </button>
        </div>

        {activeTab === 'analysis' && (
             <div className="flex gap-2">
                <Button 
                    variant="outline" 
                    className="!py-2 !px-3 text-xs flex items-center gap-1"
                    onClick={() => handleExport('png')}
                    disabled={isExporting}
                >
                   {isExporting ? '...' : '📸 PNG'}
                </Button>
                <Button 
                    variant="outline" 
                    className="!py-2 !px-3 text-xs flex items-center gap-1"
                    onClick={() => handleExport('pdf')}
                    disabled={isExporting}
                >
                   {isExporting ? '...' : '📄 PDF'}
                </Button>
             </div>
        )}
      </div>

      {activeTab === 'log' && (
        <div className="animate-fade-in">
          {!isAdding ? (
            <>
              {/* Daily Summary Card */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-6 flex justify-between items-center">
                <div>
                   <h3 className="font-bold text-slate-500 text-sm uppercase">Calories Remaining</h3>
                   <div className="text-4xl font-black text-slate-800">
                     {Math.max(0, Math.round(targets.calories - consumedMacros.calories))}
                   </div>
                </div>
                <div className="text-right">
                   <div className="text-sm text-slate-500">Eaten</div>
                   <div className="font-bold text-xl text-brand-600">{Math.round(consumedMacros.calories)} kcal</div>
                </div>
              </div>

              {/* Action Buttons Row */}
              <div className="grid grid-cols-2 gap-4 mb-6">
                  <button 
                    onClick={() => setIsAddingSunlight(true)}
                    className="py-3 bg-amber-50 hover:bg-amber-100 border border-amber-200 text-amber-800 rounded-xl font-bold transition-all flex items-center justify-center gap-2"
                  >
                    <span>☀️</span> Log Sunlight
                  </button>
                  <button 
                    onClick={() => setIsMealBuilderOpen(true)}
                    className="py-3 bg-indigo-50 hover:bg-indigo-100 border border-indigo-200 text-indigo-800 rounded-xl font-bold transition-all flex items-center justify-center gap-2"
                  >
                    <span>✨</span> Smart Builder
                  </button>
              </div>

              <div className="space-y-6">
                {MEAL_TYPES.map(type => {
                  const mealLogs = logs.filter(l => l.type === type);
                  const mealCals = mealLogs.reduce((acc, l) => acc + l.food.calories, 0);

                  return (
                    <div key={type} className="bg-white rounded-xl border border-slate-200 overflow-hidden">
                      <div className="bg-slate-50 p-4 flex justify-between items-center border-b border-slate-100">
                        <h4 className="font-bold text-slate-800">{type}</h4>
                        <span className="text-sm font-medium text-slate-500">{mealCals} kcal</span>
                      </div>
                      <div className="divide-y divide-slate-100">
                        {mealLogs.length === 0 ? (
                          <div className="p-4 text-center text-slate-400 text-sm italic">No food logged</div>
                        ) : (
                          mealLogs.map((log, index) => (
                            <div key={`${log.id}-${index}`} className="p-4 flex justify-between items-center hover:bg-slate-50 transition-colors group">
                               <div className="flex-1">
                                 <div className="font-medium text-slate-800">
                                   {log.food.name} 
                                   <span className="text-brand-600 bg-brand-50 px-2 py-0.5 rounded-full text-xs ml-2 font-bold">
                                     {log.food.servingSize || '1 serving'}
                                   </span>
                                 </div>
                                 <div className="text-xs text-slate-400">
                                   {log.food.calories > 0 && `P: ${log.food.protein}g • C: ${log.food.carbs}g • F: ${log.food.fat}g`}
                                   {log.food.micros?.['Vitamin D'] ? ` • Vitamin D: ${log.food.micros['Vitamin D']}mcg` : ''}
                                 </div>
                               </div>
                               <div className="flex items-center gap-4">
                                   <div className="font-bold text-slate-600">{log.food.calories}</div>
                                   <div className="flex gap-2">
                                       <button 
                                         onClick={(e) => { e.stopPropagation(); setEditingLog(log); }}
                                         className="p-1.5 text-slate-400 hover:text-brand-600 hover:bg-brand-50 rounded-lg"
                                         title="Edit"
                                       >
                                         <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>
                                       </button>
                                       <button 
                                         onClick={(e) => { e.stopPropagation(); deleteLog(log.id); }}
                                         className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
                                         title="Delete"
                                       >
                                         <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                                       </button>
                                   </div>
                               </div>
                            </div>
                          ))
                        )}
                        <button 
                          onClick={() => { setSelectedMeal(type); setIsAdding(true); }}
                          className="w-full p-3 text-sm font-bold text-brand-600 hover:bg-brand-50 transition-colors text-center"
                        >
                          + Add Food
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </>
          ) : (
            <div className="bg-white rounded-2xl shadow-lg border border-slate-100 p-6 animate-fade-in-up">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-slate-800">Add to {selectedMeal}</h3>
                <button onClick={() => setIsAdding(false)} className="text-slate-400 hover:text-slate-600">Cancel</button>
              </div>

              {/* AI Input */}
              <div className="mb-8">
                 <label className="block text-sm font-bold text-slate-700 mb-2">✨ Quick Add with AI (Any measure)</label>
                 <div className="flex gap-2">
                   <input 
                     type="text"
                     value={aiInput}
                     onChange={e => setAiInput(e.target.value)}
                     placeholder="e.g., 200g chicken, 1.5 cups rice, 3oz salmon, 1 tbsp olive oil"
                     className="flex-1 p-3 border-2 border-slate-200 rounded-xl focus:border-brand-500 focus:outline-none"
                     onKeyDown={e => e.key === 'Enter' && handleAiParse()}
                   />
                   <Button onClick={handleAiParse} disabled={isAiLoading || !aiInput}>
                     {isAiLoading ? '...' : 'Add'}
                   </Button>
                 </div>
                 <p className="text-xs text-slate-400 mt-2">
                   You can use grams (g), ounces (oz), cups, tablespoons, or any other unit.
                 </p>
              </div>

              <div className="border-t border-slate-100 pt-6">
                <label className="block text-sm font-bold text-slate-700 mb-2">Or choose from list</label>
                <input 
                  type="text" 
                  placeholder="Search foods..." 
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                  className="w-full p-3 border-2 border-slate-200 rounded-xl mb-4 focus:border-brand-500 focus:outline-none"
                />
                <div className="space-y-2 max-h-60 overflow-y-auto pr-2">
                  {MOCK_COMMON_FOODS.filter(f => f.name.toLowerCase().includes(searchQuery.toLowerCase())).map(food => (
                     <div key={food.id} className="flex justify-between items-center p-3 border border-slate-100 rounded-lg hover:border-brand-300 cursor-pointer group" onClick={() => handleManualAdd(food)}>
                        <div>
                          <div className="font-bold text-slate-700 group-hover:text-brand-700">
                             {food.name}
                             <span className="ml-2 text-xs font-normal text-slate-400">({food.servingSize})</span>
                          </div>
                          <div className="text-xs text-slate-400">{food.calories} kcal</div>
                        </div>
                        <div className="w-6 h-6 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-colors">+</div>
                     </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'analysis' && (
        <div className="animate-fade-in space-y-8" ref={reportRef}>

           {/* Micronutrient Score Card */}
           <section className="bg-gradient-to-br from-indigo-500 to-purple-600 p-6 rounded-3xl shadow-lg text-white">
             <div className="flex justify-between items-center mb-4">
                <div>
                   <h3 className="text-xl font-bold">Micronutrient Quality Score</h3>
                   <p className="text-indigo-100 text-sm opacity-90">Based on your intake of essential vitamins & minerals.</p>
                </div>
                <div className="text-right">
                   <div className="text-5xl font-black">{microScore}</div>
                   <div className="text-xs font-bold uppercase tracking-wider opacity-75">/ 100</div>
                </div>
             </div>

             {/* Simple Score Visual */}
             <div className="h-2 bg-black/20 rounded-full overflow-hidden mb-4">
                <div 
                   className={`h-full transition-all duration-1000 ${
                       microScore >= 80 ? 'bg-green-400' : 
                       microScore >= 50 ? 'bg-yellow-400' : 'bg-red-400'
                   }`} 
                   style={{ width: `${microScore}%` }} 
                />
             </div>

             <div className="flex gap-2 flex-wrap">
                {PRIORITY_MICROS.map(key => {
                    const info = NUTRIENT_INFO[key];
                    const current = consumedMicros[key] || 0;
                    const isMet = info && current >= (info.targetVal || 0);
                    return (
                        <span key={key} className={`text-[10px] px-2 py-1 rounded-full font-bold border ${isMet ? 'bg-green-400/20 border-green-400 text-green-100' : 'bg-white/10 border-white/10 text-white/50'}`}>
                           {key} {isMet && '✓'}
                        </span>
                    )
                })}
             </div>
           </section>

           {/* Macros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
             <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
               📊 Macro Targets
             </h3>
             <ProgressBar 
               label="Protein" 
               current={consumedMacros.protein} 
               target={targets.protein} 
               unit="g"
               colorClass="bg-blue-500" 
             />
             <ProgressBar 
               label="Carbohydrates" 
               current={consumedMacros.carbs} 
               target={targets.carbs} 
               unit="g"
               colorClass="bg-amber-400" 
             />
             <ProgressBar 
               label="Fats" 
               current={consumedMacros.fat} 
               target={targets.fat} 
               unit="g"
               colorClass="bg-rose-400" 
             />
             <ProgressBar 
               label="Fiber" 
               current={consumedMicros["Fiber"] || 0} 
               target={NUTRIENT_INFO["Fiber"].targetVal || 30} 
               unit="g"
               colorClass="bg-emerald-500" 
             />
             <ProgressBar 
               label="Sugar" 
               current={consumedMicros["Sugar"] || 0} 
               target={NUTRIENT_INFO["Sugar"].targetVal || 50} 
               unit="g"
               colorClass="bg-purple-400" 
             />
           </section>

           {/* Micros */}
           <section className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-2">Micronutrient Breakdown</h3>
              <p className="text-sm text-slate-500 mb-6">Tap any nutrient to learn more about why you need it.</p>

              <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                 {/* Combine static list keys with consumed keys to ensure we show everything relevant.
                     We also explicitly filter out macros that are already shown above.
                  */}
                 {Array.from(new Set([...Object.keys(consumedMicros), ...Object.keys(NUTRIENT_INFO)])).filter(k => !['Protein','Carbohydrates','Fats','Fiber','Sugar'].includes(k)).map(key => {
                    const amount = consumedMicros[key] || 0;
                    const info = NUTRIENT_INFO[key];
                    const hasData = !!info;
                    const target = info?.targetVal;
                    const unit = info?.unit || '';

                    return (
                      <button 
                        key={key}
                        onClick={() => setSelectedNutrient(key)}
                        disabled={!hasData}
                        className={`p-4 rounded-xl border-2 text-left transition-all hover:scale-[1.02] active:scale-95 flex flex-col justify-between min-h-[100px]
                          ${hasData ? 'border-slate-100 hover:border-brand-300 bg-slate-50' : 'border-transparent opacity-50 cursor-default'}
                        `}
                      >
                         <div className="text-xs font-bold text-slate-400 uppercase mb-1 truncate w-full" title={key}>{key}</div>

                         <div>
                            <div className="text-lg font-black text-slate-800 flex items-baseline gap-0.5">
                              {amount > 0 ? Math.round(amount * 10) / 10 : '-'}
                              {unit && <span className="text-xs font-normal text-slate-500">{unit}</span>}
                            </div>

                            {target && amount > 0 && (
                                <div className={`text-xs font-bold mt-1 ${
                                    (amount / target) > 1.2 ? 'text-amber-500' : 
                                    (amount / target) > 0.8 ? 'text-green-500' : 'text-slate-400'
                                }`}>
                                    {Math.round((amount / target) * 100)}% DV
                                </div>
                            )}
                         </div>
                      </button>
                    )
                 })}
              </div>
           </section>

           <NutrientDetailModal />
        </div>
      )}
      <EditLogModal />
      <SunlightModal />
      <SmartMealBuilderModal />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { UserProfile, CalculatedMetrics, WellnessPlan, GamificationState, ActivityLevel, Goal, MealLog, MealType, FoodItem } from './types';
import { generateWellnessPlan } from './services/geminiService';

const STORAGE_KEY = 'vitalquest_user_data_v1';

const calculateMetrics = (profile: UserProfile): CalculatedMetrics => {
  // Mifflin-St Jeor Equation
  const s = profile.gender === 'Male' ? 5 : -161;
  const bmr = (10 * profile.weightKg) + (6.25 * profile.heightCm) - (5 * profile.age) + s;

  // Activity Multipliers
  let multiplier = 1.2;

  // Refined Logic: Use Steps if provided as a more accurate proxy for NEAT + Activity
  if (profile.dailySteps && profile.dailySteps > 0) {
      const steps = profile.dailySteps;
      if (steps < 5000) multiplier = 1.2;
      else if (steps < 7500) multiplier = 1.375;
      else if (steps < 10000) multiplier = 1.55;
      else if (steps < 15000) multiplier = 1.725;
      else multiplier = 1.9;
  } else {
    // Fallback to standard selection
    switch (profile.activityLevel) {
        case ActivityLevel.Light: multiplier = 1.375; break;
        case ActivityLevel.Moderate: multiplier = 1.55; break;
        case ActivityLevel.VeryActive: multiplier = 1.725; break;
        case ActivityLevel.ExtraActive: multiplier = 1.9; break;
        default: multiplier = 1.2;
    }
  }

  let tdee = bmr * multiplier;

  // Goal Adjustments
  if (profile.goal === Goal.FatLoss) tdee -= 500;
  if (profile.goal === Goal.MuscleGain) tdee += 300;

  const heightM = profile.heightCm / 100;
  const bmi = profile.weightKg / (heightM * heightM);

  let bmiCategory = 'Normal';
  if (bmi < 18.5) bmiCategory = 'Underweight';
  else if (bmi >= 25 && bmi < 30) bmiCategory = 'Overweight';
  else if (bmi >= 30) bmiCategory = 'Obese';

  // Macro Calculation (Simplified)
  // Protein: High for muscle/fat loss
  let proteinPerKg = 1.6;
  if (profile.goal === Goal.MuscleGain || profile.goal === Goal.FatLoss) proteinPerKg = 2.0;

  const proteinGrams = Math.round(profile.weightKg * proteinPerKg);
  const fatGrams = Math.round((tdee * 0.25) / 9); // ~25% calories from fat
  const carbGrams = Math.round((tdee - (proteinGrams * 4) - (fatGrams * 9)) / 4);

  return { 
    bmi, 
    bmr, 
    tdee: Math.round(tdee), 
    bmiCategory,
    macros: {
      protein: proteinGrams,
      fat: fatGrams,
      carbs: carbGrams
    }
  };
};

const initialGamification: GamificationState = {
  xp: 0,
  level: 1,
  streak: 1,
  completedQuestIds: [],
  badges: []
};

const App: React.FC = () => {
  const [view, setView] = useState<'onboarding' | 'dashboard'>('onboarding');
  const [isLoading, setIsLoading] = useState(false);

  // Application State
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [metrics, setMetrics] = useState<CalculatedMetrics | null>(null);
  const [plan, setPlan] = useState<WellnessPlan | null>(null);
  const [gamification, setGamification] = useState<GamificationState>(initialGamification);
  const [foodLogs, setFoodLogs] = useState<MealLog[]>([]);

  // Load from LocalStorage on mount
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        if (parsed.profile) {
          setProfile(parsed.profile);
          setMetrics(parsed.metrics);
          setPlan(parsed.plan);
          setGamification(parsed.gamification || initialGamification);
          setFoodLogs(parsed.foodLogs || []);
          setView('dashboard');
        }
      } catch (e) {
        console.error("Failed to parse saved user data", e);
      }
    }
  }, []);

  // Save to LocalStorage on updates
  useEffect(() => {
    // Only save if we have an active session to avoid overwriting during reset
    if (profile && metrics && plan) {
      const dataToSave = {
        profile,
        metrics,
        plan,
        gamification,
        foodLogs
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
    }
  }, [profile, metrics, plan, gamification, foodLogs]);

  const handleOnboardingComplete = async (userProfile: UserProfile) => {
    setIsLoading(true);
    setProfile(userProfile);

    // 1. Calculate basic physics locally (immediate feedback potential)
    const calculated = calculateMetrics(userProfile);
    setMetrics(calculated);

    // 2. AI Generation
    try {
      const generatedPlan = await generateWellnessPlan(userProfile);
      setPlan(generatedPlan);
      setView('dashboard');
    } catch (e) {
      alert("Failed to generate plan. Please check API Key configuration.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddFood = (type: MealType, food: FoodItem) => {
    // Generate a robust unique ID
    const uniqueId = `log-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const newLog: MealLog = {
      id: uniqueId,
      type,
      food,
      timestamp: Date.now()
    };
    setFoodLogs(prev => [...prev, newLog]);
  };

  const handleUpdateLog = (updatedLog: MealLog) => {
    setFoodLogs(prev => prev.map(log => log.id === updatedLog.id ? updatedLog : log));
  };

  const handleDeleteLog = (logId: string) => {
    setFoodLogs(prev => prev.filter(log => log.id !== logId));
  };

  const handleReset = () => {
    if (window.confirm("Are you sure you want to reset your profile? All progress and logs will be lost.")) {
      localStorage.removeItem(STORAGE_KEY);
      // Reset state and force a reload for a clean slate
      setProfile(null);
      setMetrics(null);
      setPlan(null);
      setFoodLogs([]);
      setGamification(initialGamification);
      setView('onboarding');
      window.location.reload();
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">

      {/* Navbar */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-brand-500 rounded-lg flex items-center justify-center text-white font-bold text-xl">
              V
            </div>
            <span className="font-extrabold text-xl tracking-tight text-slate-900">Vital<span className="text-brand-600">Quest</span></span>
          </div>
          {view === 'dashboard' && (
             <div className="text-sm font-semibold text-slate-500 hidden sm:block">
               {gamification.xp} XP
             </div>
          )}
        </div>
      </nav>

      <main className="flex-grow">
        {view === 'onboarding' && (
          <div className="py-12 px-4">
             <div className="text-center mb-10">
               <h1 className="text-4xl font-extrabold text-slate-900 mb-4">Your Wellness Journey Starts Here.</h1>
               <p className="text-lg text-slate-600 max-w-2xl mx-auto">
                 Get a personalized, evidence-based plan tailored to your body, goals, and lifestyle. 
                 No generic advice—just science and daily quests.
               </p>
             </div>
             <Onboarding onComplete={handleOnboardingComplete} isLoading={isLoading} />
          </div>
        )}

        {view === 'dashboard' && profile && metrics && plan && (
          <Dashboard 
            profile={profile}
            metrics={metrics}
            plan={plan}
            gamification={gamification}
            onUpdateGamification={setGamification}
            onReset={handleReset}
            foodLogs={foodLogs}
            onAddFood={handleAddFood}
            onUpdateLog={handleUpdateLog}
            onDeleteLog={handleDeleteLog}
          />
        )}
      </main>

    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Button } from './ui/Button';
import { FoodItem, MealLog, MealType, MacroTargets, MealSuggestion } from '../types';
import { MOCK_COMMON_FOODS, NUTRIENT_INFO } from '../data/nutrientData';
import { parseFoodLog, suggestMeals } from '../services/geminiService';
// @ts-ignore
import html2canvas from 'html2canvas';
// @ts-ignore
import { jsPDF } from 'jspdf';

interface NutritionTrackerProps {
  logs: MealLog[];
  onAddFood: (meal: MealType, food: FoodItem) => void;
  onUpdateLog: (log: MealLog) => void;
  onDeleteLog: (logId: string) => void;
  targets: MacroTargets;
}

const MEAL_TYPES: MealType[] = ['Breakfast', 'Lunch', 'Dinner', 'Snack'];

const PRIORITY_MICROS = [
  "Fiber", "Vitamin C", "Vitamin D", "Magnesium", "Potassium", 
  "Iron", "Calcium", "Vitamin B12", "Zinc", "Omega-3"
];

// List of nutrients we explicitly want to hide
const HIDDEN_MICROS = ["Chromium", "Molybdenum"];

export const NutritionTracker: React.FC<NutritionTrackerProps> = ({ logs, onAddFood, onUpdateLog, onDeleteLog, targets }) => {
  const [activeTab, setActiveTab] = useState<'log' | 'analysis'>('log');
  const [isAdding, setIsAdding] = useState(false);
  const [isAddingSunlight, setIsAddingSunlight] = useState(false);
  const [isMealBuilderOpen, setIsMealBuilderOpen] = useState(false);

  const [selectedMeal, setSelectedMeal] = useState<MealType>('Breakfast');
  const [searchQuery, setSearchQuery] = useState('');
  const [aiInput, setAiInput] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [selectedNutrient, setSelectedNutrient] = useState<string | null>(null);

  // Export state
  const reportRef = useRef<HTMLDivElement>(null);
  const [isExporting, setIsExporting] = useState(false);

  // Edit State
  const [editingLog, setEditingLog] = useState<MealLog | null>(null);

  // -- Derived Data --
  const consumedMacros = logs.reduce((acc, log) => ({
    calories: acc.calories + log.food.calories,
    protein: acc.protein + log.food.protein,
    carbs: acc.carbs + log.food.carbs,
    fat: acc.fat + log.food.fat,
  }), { calories: 0, protein: 0, carbs: 0, fat: 0 });

  // Consolidate micros
  const consumedMicros: Record<string, number> = {};
  logs.forEach(log => {
    if (log.food.micros) {
      Object.entries(log.food.micros).forEach(([name, amount]) => {
        if (!HIDDEN_MICROS.includes(name)) {
          consumedMicros[name] = (consumedMicros[name] || 0) + (amount as number);
        }
      });
    }
  });

  const calculateMicroScore = () => {
    let totalRatio = 0;
    let count = 0;

    PRIORITY_MICROS.forEach(key => {
        const info = NUTRIENT_INFO[key];
        if (!info || !info.targetVal) return;

        const current = consumedMicros[key] || 0;
        // Cap at 1.0 (100%) so excess doesn't compensate for deficiency elsewhere
        const ratio = Math.min(current / info.targetVal, 1);
        totalRatio += ratio;
        count++;
    });

    return count === 0 ? 0 : Math.round((totalRatio / count) * 100);
  };

  const microScore = calculateMicroScore();

  // -- Handlers --
  const handleAiParse = async () => {
    if(!aiInput.trim()) return;
    setIsAiLoading(true);
    const foods = await parseFoodLog(aiInput);
    foods.forEach(f => onAddFood(selectedMeal, f));
    setIsAiLoading(false);
    setAiInput('');
    setIsAdding(false);
  };

  const handleManualAdd = (food: FoodItem) => {
    onAddFood(selectedMeal, food);
    setIsAdding(false);
  };

  const saveEditedLog = () => {
    if (editingLog) {
      onUpdateLog(editingLog);
      setEditingLog(null);
    }
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Are you sure you want to delete this item?")) {
        onDeleteLog(id);
    }
  };

  const handleExport = async (type: 'png' | 'pdf') => {
    if (!reportRef.current) return;
    setIsExporting(true);

    try {
      // Small delay to ensure render
      await new Promise(resolve => setTimeout(resolve, 100));

      const canvas = await html2canvas(reportRef.current, {
        scale: 2, // Better resolution
        backgroundColor: '#ffffff',
        logging: false
      });

      if (type === 'png') {
        const image = canvas.toDataURL("image/png");
        const link = document.createElement('a');
        link.href = image;
        link.download = `VitalQuest-Report-${new Date().toISOString().split('T')[0]}.png`;
        link.click();
      } else {
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('p', 'mm', 'a4');
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

        pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
        pdf.save(`VitalQuest-Report-${new Date().toISOString().split('T')[0]}.pdf`);
      }
    } catch (err) {
      console.error("Export failed", err);
      alert("Failed to export report.");
    } finally {
      setIsExporting(false);
    }
  };

  // -- Render Helpers --
  const ProgressBar = ({ current, target, colorClass, label, unit }: any) => {
    const pct = Math.min((current / target) * 100, 100);
    return (
      <div className="mb-4 break-inside-avoid">
        <div className="flex justify-between text-sm font-bold text-slate-700 mb-1">
          <span>{label}</span>
          <span>{Math.round(current)} / {Math.round(target)}{unit}</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className={`h-full transition-all duration-500 ${colorClass}`} style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const NutrientDetailModal = () => {
    if (!selectedNutrient) return null;
    const info = NUTRIENT_INFO[selectedNutrient];
    return (
      <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setSelectedNutrient(null)}>
        <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl" onClick={e => e.stopPropagation()}>
          <div className="flex justify-between items-start mb-4">
             <h3 className="text-2xl font-black text-slate-800">{selectedNutrient}</h3>
             <button onClick={() => setSelectedNutrient(null)} className="text-slate-400 hover:text-slate-800 text-xl font-bold">×</button>
          </div>

          {info ? (
            <div className="space-y-4">
              <p className="text-slate-600 leading-relaxed">{info.description}</p>

              <div className="flex justify-between items-center bg-slate-50 p-4 rounded-xl border border-slate-100">
                 <span className="font-bold text-slate-600">Daily Target</span>
                 <span className="font-black text-xl text-slate-800">{info.dailyValue}</span>
              </div>

              <div>
                <h4 className="font-bold text-sm text-brand-600 uppercase mb-2">Good Sources</h4>
                <div className="flex flex-wrap gap-2">
                  {info.sources.map(s => (
                    <span key={s} className="bg-brand-50 text-brand-800 px-3 py-1 rounded-full text-sm font-medium border border-brand-100">{s}</span>
                  ))}
                </div>
              </div>

              {info.caution && (
                <div className="bg-amber-50 p-4 rounded-xl border border-amber-100 text-amber-800 text-sm">
                  <strong>⚠️ Note: </strong> {info.caution}
                </div>
              )}
            </div>
          ) : (
            <p>No educational data available for this nutrient.</p>
          )}
        </div>
      </div>
    );
  };

  const SunlightModal = () => {
    if (!isAddingSunlight) return null;
    const [mins, setMins] = useState('');

    const handleSave = () => {
        const val = parseInt(mins);
        if (val > 0) {
             const vitD = Math.round(val * 0.7); 

             const sunItem: FoodItem = {
                 id: `sun-${Date.now()}`,
                 name: '☀️ Sunlight Exposure',
                 servingSize: `${val} mins`,
                 calories: 0,
                 protein: 0,
                 carbs: 0,
                 fat: 0,
                 micros: { "Vitamin D": vitD }
             };
             onAddFood('Snack', sunItem);
             setIsAddingSunlight(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setIsAddingSunlight(false)}>
            <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl space-y-4" onClick={e => e.stopPropagation()}>
                 <div className="flex justify-between items-center">
                    <h3 className="text-xl font-bold text-slate-800">☀️ Log Sunlight</h3>
                    <button onClick={() => setIsAddingSunlight(false)} className="text-slate-400 hover:text-slate-600">×</button>
                 </div>
                 <p className="text-sm text-slate-500">
                    Sun exposure helps your body produce Vitamin D. 
                 </p>

                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Duration (Minutes)</label>
                    <input 
                        type="number"
                        autoFocus
                        className="w-full p-3 border-2 border-slate-200 rounded-xl focus:border-amber-400 focus:outline-none text-lg font-bold text-slate-800"
                        placeholder="e.g. 15"
                        value={mins}
                        onChange={e => setMins(e.target.value)}
                        onKeyDown={e => e.key === 'Enter' && handleSave()}
                    />
                 </div>

                 <Button variant="primary" className="bg-amber-500 hover:bg-amber-600 border-amber-700 shadow-amber-500/30" fullWidth onClick={handleSave}>
                    Add Vitamin D
                 </Button>
            </div>
        </div>
    );
  };

  const SmartMealBuilderModal = () => {
    if (!isMealBuilderOpen) return null;
    const [criteria, setCriteria] = useState('');
    const [suggestions, setSuggestions] = useState<MealSuggestion[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [targetMeal, setTargetMeal] = useState<MealType>('Lunch');

    const handleGenerate = async () => {
        if (!criteria.trim()) return;
        setIsLoading(true);
        const results = await suggestMeals(criteria);
        setSuggestions(results);
        setIsLoading(false);
    };

    const handleAddSuggestion = (s: MealSuggestion) => {
        const item: FoodItem = {
            id: `suggestion-${Date.now()}`,
            name: s.name,
            servingSize: "1 Meal",
            calories: s.calories,
            protein: s.protein,
            carbs: s.carbs,
            fat: s.fat,
            micros: s.micros
        };
        onAddFood(targetMeal, item);
        setIsMealBuilderOpen(false); 
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setIsMealBuilderOpen(false)}>
            <div className="bg-white rounded-3xl p-6 max-w-2xl w-full shadow-2xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center mb-6">
                    <div>
                      <h3 className="text-2xl font-black text-slate-800 flex items-center gap-2">
                        ✨ Smart Meal Builder
                      </h3>
                    </div>
                    <button onClick={() => setIsMealBuilderOpen(false)} className="text-slate-400 hover:text-slate-800 text-2xl font-bold">×</button>
                </div>

                <div className="mb-6">
                    <label className="block text-sm font-bold text-slate-700 mb-2">Describe what you need</label>
                    <textarea 
                        className="w-full p-4 border-2 border-slate-200 rounded-xl focus:border-brand-500 focus:outline-none text-slate-800 mb-3"
                        placeholder="e.g., 'A high protein vegan breakfast under 400 calories'"
                        rows={2}
                        value={criteria}
                        onChange={e => setCriteria(e.target.value)}
                    />

                    <div className="flex gap-4 items-center">
                       <select 
                         value={targetMeal}
                         onChange={e => setTargetMeal(e.target.value as MealType)}
                         className="p-3 border-2 border-slate-200 rounded-xl font-medium bg-white"
                       >
                           {MEAL_TYPES.map(t => <option key={t} value={t}>Plan for {t}</option>)}
                       </select>
                       <Button 
                         onClick={handleGenerate} 
                         disabled={isLoading || !criteria}
                         className="flex-1"
                       >
                         {isLoading ? 'Thinking...' : 'Generate Ideas'}
                       </Button>
                    </div>
                </div>

                {suggestions.length > 0 && (
                    <div className="space-y-4 animate-fade-in-up">
                        <h4 className="font-bold text-slate-400 uppercase text-xs tracking-wider">Suggestions</h4>
                        <div className="grid gap-4">
                            {suggestions.map((s, idx) => (
                                <div key={idx} className="border border-slate-200 rounded-2xl p-5 hover:border-brand-300 transition-colors bg-slate-50">
                                    <div className="flex justify-between items-start mb-2">
                                        <h5 className="font-bold text-xl text-brand-800">{s.name}</h5>
                                        <Button variant="outline" className="!py-1 !px-3 text-xs" onClick={() => handleAddSuggestion(s)}>
                                            Add to Log
                                        </Button>
                                    </div>
                                    <p className="text-slate-600 text-sm mb-3">{s.description}</p>
                                    <div className="flex gap-3 text-sm">
                                        <span className="font-bold text-slate-800">{s.calories} kcal</span>
                                        <span className="text-slate-500">P: <span className="font-semibold text-slate-700">{s.protein}g</span></span>
                                        <span className="text-slate-500">C: <span className="font-semibold text-slate-700">{s.carbs}g</span></span>
                                        <span className="text-slate-500">F: <span className="font-semibold text-slate-700">{s.fat}g</span></span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
  };

  const EditLogModal = () => {
    if (!editingLog) return null;

    const updateField = (field: keyof FoodItem, val: string | number) => {
        setEditingLog(prev => {
            if (!prev) return null;
            return {
                ...prev,
                food: {
                    ...prev.food,
                    [field]: val
                }
            };
        });
    };

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={() => setEditingLog(null)}>
            <div className="bg-white rounded-2xl p-6 max-w-sm w-full shadow-2xl space-y-4" onClick={e => e.stopPropagation()}>
                <h3 className="text-xl font-bold text-slate-800">Edit Entry</h3>
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Food Name</label>
                    <input className="w-full p-2 border border-slate-200 rounded-lg" value={editingLog.food.name} onChange={e => updateField('name', e.target.value)} />
                </div>
                <div className="flex gap-2 pt-2">
                    <Button variant="outline" fullWidth onClick={() => setEditingLog(null)}>Cancel</Button>
                    <Button variant="primary" fullWidth onClick={saveEditedLog}>Save</Button>
                </div>
            </div>
        </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex gap-2 bg-slate-100 p-1 rounded-xl w-fit">
            <button onClick={() => setActiveTab('log')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'log' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}>Food Log</button>
            <button onClick={() => setActiveTab('analysis')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'analysis' ? 'bg-white shadow text-slate-900' : 'text-slate-500'}`}>Analysis</button>
        </div>
      </div>

      {activeTab === 'log' && (
        <div className="animate-fade-in">
          {!isAdding ? (
            <>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 mb-6 flex justify-between items-center">
                <div>
                   <h3 className="font-bold text-slate-500 text-sm uppercase">Calories Remaining</h3>
                   <div className="text-4xl font-black text-slate-800">{Math.max(0, Math.round(targets.calories - consumedMacros.calories))}</div>
                </div>
                <div className="text-right">
                   <div className="text-sm text-slate-500">Eaten</div>
                   <div className="font-bold text-xl text-brand-600">{Math.round(consumedMacros.calories)} kcal</div>
