                                 <div className="font-medium text-slate-800">{log.food.name} <span className="text-brand-600 text-xs ml-2">({log.food.servingSize})</span></div>
                                 <div className="text-xs text-slate-400">P: {log.food.protein}g • C: {log.food.carbs}g • F: {log.food.fat}g</div>
                               </div>
                               <div className="flex items-center gap-4">
                                   <div className="font-bold text-slate-600">{log.food.calories}</div>
                                   <div className="flex gap-2">
                                       <button onClick={() => setEditingLog(log)} className="p-1.5 text-slate-300 hover:text-brand-600">
                                         <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>
                                       </button>
                                       <button onClick={(e) => handleDelete(e, log.id)} className="p-1.5 text-slate-300 hover:text-red-600">
                                         <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                                       </button>
                                   </div>
                               </div>
                            </div>
                          ))
                        )}
                        <button onClick={() => { setSelectedMeal(type); setIsAdding(true); }} className="w-full p-3 text-sm font-bold text-brand-600 hover:bg-brand-50 transition-colors">+ Add Food</button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </>
          ) : (
            <div className="bg-white rounded-2xl p-6 animate-fade-in-up">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-slate-800">Add to {selectedMeal}</h3>
                <button onClick={() => setIsAdding(false)} className="text-slate-400 hover:text-slate-600">Cancel</button>
              </div>
