                 <label className="block text-sm font-bold text-slate-700 mb-2">✨ Quick AI Add</label>
                 <div className="flex gap-2">
                   <input type="text" value={aiInput} onChange={e => setAiInput(e.target.value)} placeholder="e.g., 2 eggs and toast" className="flex-1 p-3 border-2 rounded-xl" />
